# ============================================================================
# Custom Bin Colormap - Bin 1 is always GREEN (good bin)
# ============================================================================
from matplotlib.colors import ListedColormap, BoundaryNorm
import matplotlib.cm as cm

def get_bin_colormap(unique_bins):
    """
    Create a custom colormap for binning where Bin 1 is always GREEN (good bin).
    Other bins get distinct colors from a predefined palette.

    Args:
        unique_bins: Array or list of unique bin values in the data

    Returns:
        cmap: ListedColormap with Bin 1 as green
        norm: BoundaryNorm for proper bin value mapping
    """
    # Predefined colors: Bin 1 = Green, others = distinct colors for fail bins
    bin_colors = {
        1: '#4CAF50',   # Green - GOOD BIN
        2: '#F44336',   # Red
        3: '#FF9800',   # Orange
        4: '#9C27B0',   # Purple
        5: '#2196F3',   # Blue
        6: '#FFEB3B',   # Yellow
        7: '#795548',   # Brown
        8: '#607D8B',   # Gray-Blue
        9: '#E91E63',   # Pink
        10: '#00BCD4',  # Cyan
        11: '#8BC34A',  # Light Green
        12: '#FF5722',  # Deep Orange
        13: '#673AB7',  # Deep Purple
        14: '#03A9F4',  # Light Blue
        15: '#CDDC39',  # Lime
        16: '#9E9E9E',  # Gray
    }

    # Default color for bins > 16
    default_colors = plt.cm.tab20.colors

    sorted_bins = sorted([b for b in unique_bins if not np.isnan(b)])

    if len(sorted_bins) == 0:
        return 'viridis', None

    colors = []
    for bin_val in sorted_bins:
        bin_int = int(bin_val)
        if bin_int in bin_colors:
            colors.append(bin_colors[bin_int])
        else:
            # Use tab20 colors for bins > 16
            color_idx = (bin_int - 1) % len(default_colors)
            colors.append(default_colors[color_idx])

    cmap = ListedColormap(colors)

    # Create boundaries for discrete color mapping
    boundaries = sorted_bins + [sorted_bins[-1] + 1]
    norm = BoundaryNorm(boundaries, cmap.N)

    return cmap, norm

# ============================================================================
# Multithreading Support with Priority Queue
# ============================================================================

# Thread pool for background loading
MAX_WORKERS = 4  # Number of parallel loading threads
thread_pool = ThreadPoolExecutor(max_workers=MAX_WORKERS)

# Priority levels (lower number = higher priority)
PRIORITY_HIGH = 1
PRIORITY_NORMAL = 2
PRIORITY_LOW = 3


@dataclass(order=True)
class PrioritizedTask:
    """Task with priority for the loading queue"""
    priority: int
    task_id: int = field(compare=False)
    func: Callable = field(compare=False)
    args: tuple = field(compare=False, default=())
    kwargs: dict = field(compare=False, default_factory=dict)
    callback: Optional[Callable] = field(compare=False, default=None)
    error_callback: Optional[Callable] = field(compare=False, default=None)


# Global task counter for unique task IDs
_task_counter = 0
_task_lock = threading.Lock()

# Loading state tracking
_loading_tasks = {}
_loading_lock = threading.Lock()


def get_next_task_id():
    """Get a unique task ID"""
    global _task_counter
    with _task_lock:
        _task_counter += 1
        return _task_counter


def submit_loading_task(func, args=(), kwargs=None, callback=None,
                        error_callback=None, priority=PRIORITY_NORMAL):
    """Submit a loading task to the thread pool with priority"""
    if kwargs is None:
        kwargs = {}

    task_id = get_next_task_id()

    def wrapped_task():
        try:
            result = func(*args, **kwargs)
            if callback:
                # Schedule callback on main thread
                main_win.after(0, lambda: callback(result))
            return result
        except Exception as e:
            print(f"Error in loading task {task_id}: {e}")
            if error_callback:
                main_win.after(0, lambda: error_callback(e))
            raise

    future = thread_pool.submit(wrapped_task)

    with _loading_lock:
        _loading_tasks[task_id] = {
            'future': future,
            'priority': priority,
            'start_time': time.time()
        }

    return task_id, future


def cancel_loading_task(task_id):
    """Cancel a loading task if possible"""
    with _loading_lock:
        if task_id in _loading_tasks:
            future = _loading_tasks[task_id]['future']
            cancelled = future.cancel()
            if cancelled:
                del _loading_tasks[task_id]
            return cancelled
    return False


def get_loading_progress():
    """Get current loading progress"""
    with _loading_lock:
        total = len(_loading_tasks)
        completed = sum(1 for t in _loading_tasks.values() if t['future'].done())
        return completed, total


