def sort_test_params_numerically(items):
    """
    ZENTRALE SORTIER-FUNKTION für alle Parameter-Listen.

    Sortiert Parameter nach der numerischen test_num (10011000, 10011001, ...).
    Wird von ALLEN Tabs verwendet (Wafer, Multi-Wafer, Charac-Curve, Statistics, etc.)

    Args:
        items: Kann sein:
            - dict.items(): Liste von (test_key, test_name) Tupeln
            - list: Liste von Tupeln (test_num, name, full_name)

    Returns:
        Sortierte Liste
    """
    def sort_key(item):
        # Handle dict.items() format: (test_key, test_name)
        if isinstance(item, tuple) and len(item) >= 2:
            first = item[0]
            # Wenn erstes Element ein String ist (z.B. "test_10011000")
            if isinstance(first, str) and first.startswith("test_"):
                try:
                    return int(first.replace("test_", ""))
                except ValueError:
                    pass
            # Wenn erstes Element direkt eine Zahl ist (z.B. 10011000 aus grouped_parameters)
            elif isinstance(first, (int, float)):
                return int(first)
        return float('inf')  # Nicht-numerische ans Ende

    return sorted(items, key=sort_key)


def simplify_param_name(param_name):
    """
    Simplify parameter name by removing group/subgroup prefix and test number suffix.
    Also strips CSV '<>' duplicate name and converts coded values to readable format.

    Conversions (dynamisch, nicht hardcodiert):
    - FV0P1 → 0.1V (Force Voltage)
    - FC0P2, FCn0P2 → 0.2mA, -0.2mA (Force Current)
    - AVEEn1p8 → -1.80V
    - DACI3p0 → 3.00uA
    - DC4p59 → 4.59%
    """
    import re

    if not param_name or param_name == "Bin":
        return param_name

    name = str(param_name)

    # Remove test_XXXXX: prefix if present
    if ":" in name:
        name = name.split(":", 1)[-1].strip()

    # ============================================================
    # HANDLE CSV "<>" FORMAT - Use the long name after "<>"
    # ============================================================
    if '<>' in name:
        parts = name.split('<>')
        if len(parts) == 2:
            name = parts[1].strip()  # Use the long name (after <>)

    # Whitespace bereinigen - LEERZEICHEN ENTFERNEN
    name = re.sub(r'\s+', '', name)

    # ============================================================
    # GRUPPEN-PRÄFIX DYNAMISCH ENTFERNEN
    # Nur bekannte Gruppen-Typen am Anfang entfernen (OPTIC_, DC_, ANLG_, FUNC_, etc.)
    # NICHT beliebige XXXX_YYYY_ Patterns - die könnten Testnamen sein!
    # ============================================================
    known_group_types = ['OPTIC', 'DC', 'ANLG', 'ANALOG', 'FUNC', 'FUNCTIONAL',
                         'EFUSE', 'INIT', 'INITIALIZE', 'DIGITAL', 'POWER', 'SOT']

    # Pattern: GRUPPE_SUBGRUPPE- oder GRUPPE_SUBGRUPPE_ am Anfang
    # z.B. OPTIC_ANSI-, DC_SHORT_, ANLG_DISPLAYI-
    prefix_match = re.match(r'^([A-Z]+)_([A-Z0-9]+[-_])', name, re.IGNORECASE)
    if prefix_match:
        group_type = prefix_match.group(1).upper()
        if group_type in known_group_types:
            # Nur entfernen wenn es eine bekannte Gruppe ist
            name = name[len(prefix_match.group(0)):]

    # ============================================================
    # KODIERTE WERTE DYNAMISCH KONVERTIEREN
    # ============================================================

    # FV (Force Voltage): FV0P1 → 0.1V, FV1P8 → 1.8V
    def convert_fv(match):
        integer = match.group(1)
        decimal = match.group(2)
        return f"{integer}.{decimal}V"
    name = re.sub(r'FV(\d+)P(\d+)', convert_fv, name, flags=re.IGNORECASE)

    # FC (Force Current): FC0P2 → 0.2mA, FCn0P2 → -0.2mA
    def convert_fc(match):
        sign = '-' if match.group(1).lower() == 'n' else ''
        integer = match.group(2)
        decimal = match.group(3)
        return f"{sign}{integer}.{decimal}mA"
    name = re.sub(r'FC([np]?)(\d+)P(\d+)', convert_fc, name, flags=re.IGNORECASE)

    # AVEE (Voltage): AVEEn1p8 → -1.80V, AVEE1p8 → 1.80V
    def convert_avee(match):
        sign = '-' if match.group(1).lower() == 'n' else ''
        integer = match.group(2)
        decimal = match.group(3).ljust(2, '0')
        return f"{sign}{integer}.{decimal}V"
    name = re.sub(r'AVEE([np]?)(\d+)p(\d+)', convert_avee, name, flags=re.IGNORECASE)

    # DACI (Current): DACI3p0 → 3.00uA, DACIn0p6 → -0.60uA
    def convert_daci(match):
        sign = '-' if match.group(1).lower() == 'n' else ''
        integer = match.group(2)
        decimal = match.group(3).ljust(2, '0')
        return f"{sign}{integer}.{decimal}uA"
    name = re.sub(r'DACI([np]?)(\d+)p(\d+)', convert_daci, name, flags=re.IGNORECASE)

    # DC (Duty Cycle): DC4p59 → 4.59%
    def convert_dc(match):
        integer = match.group(1)
        decimal = match.group(2)
        return f"{integer}.{decimal}%"
    name = re.sub(r'(?<![A-Z])DC(\d+)p(\d+)', convert_dc, name, flags=re.IGNORECASE)

    # ============================================================
    # CLEANUP
    # ============================================================

    # Remove trailing test number (5+ digits at the end after underscore)
    name = re.sub(r'_\d{5,}$', '', name)

    # Remove trailing _X_X_X patterns and other noise
    name = re.sub(r'(_X)+(_|$)', '_', name)
    name = re.sub(r'_?(FREERUN|INTFRAME)_X_', '_', name, flags=re.IGNORECASE)
    name = re.sub(r'_NV_', '_', name)
    name = re.sub(r'_PEQA_', '_', name)
    name = re.sub(r'_+', '_', name)  # Doppelte _ entfernen
    name = name.strip('_')

    return name if name else param_name

    # Remove trailing _X_X_X patterns and other noise
    name = re.sub(r'(_X)+(_|$)', '_', name)
    name = re.sub(r'_NV_', '_', name)
    name = re.sub(r'_PEQA_', '_', name)
    name = name.strip('_')

    # No truncation - show full name
    return name if name else param_name


def extract_group_from_column(col_name):
    """Extract group name from column prefix with detailed subgroups.
    This is a global function used by both Wafermap and Multi-Wafermap tabs."""
    col_str = str(col_name).upper()

    # Define detailed subgroup patterns for each main group
    # Format: (pattern_to_match, group_name)
    detailed_patterns = [
        # DC subgroups
        ('DC_CONT', 'DC_CONT'),
        ('DC_LKG', 'DC_LKG'),
        ('DC_LEAKAGE', 'DC_LKG'),
        ('DC_IDD', 'DC_IDD'),
        ('DC_VDD', 'DC_VDD'),
        ('DC_IDDQ', 'DC_IDDQ'),
        ('DC_POWER', 'DC_POWER'),
        ('DC_DIODE', 'DC_DIODE'),
        ('DC_RES', 'DC_RES'),
        ('DC_CAP', 'DC_CAP'),
        ('DC_SHORT', 'DC_SHORT'),
        ('DC_OPEN', 'DC_OPEN'),
        ('DC_CLAMP', 'DC_CLAMP'),
        ('DC_PMU', 'DC_PMU'),
        ('DC_FORCE', 'DC_FORCE'),
        ('DC_MEAS', 'DC_MEAS'),

        # ANALOG subgroups
        ('ANLG_ADC', 'ANLG_ADC'),
        ('ANLG_DAC', 'ANLG_DAC'),
        ('ANLG_BANDGAP', 'ANLG_BANDGAP'),
        ('ANLG_PLL', 'ANLG_PLL'),
        ('ANLG_OSC', 'ANLG_OSC'),
        ('ANLG_LDO', 'ANLG_LDO'),
        ('ANLG_AMP', 'ANLG_AMP'),
        ('ANLG_COMP', 'ANLG_COMP'),
        ('ANLG_REF', 'ANLG_REF'),
        ('ANLG_BIAS', 'ANLG_BIAS'),
        ('ANLG_TRIM', 'ANLG_TRIM'),
        ('ANALOG_ADC', 'ANLG_ADC'),
        ('ANALOG_DAC', 'ANLG_DAC'),
        ('ANALOG_BANDGAP', 'ANLG_BANDGAP'),
        ('ANALOG_PLL', 'ANLG_PLL'),

        # OPTIC/OPTICAL subgroups
        ('OPTIC_ANSI', 'OPTIC_ANSI'),
        ('OPTIC_IEC', 'OPTIC_IEC'),
        ('OPTIC_POWER', 'OPTIC_POWER'),
        ('OPTIC_CURRENT', 'OPTIC_CURRENT'),
        ('OPTIC_THRESHOLD', 'OPTIC_THRESHOLD'),
        ('OPTIC_SLOPE', 'OPTIC_SLOPE'),
        ('OPTIC_LIV', 'OPTIC_LIV'),
        ('OPTIC_WAVE', 'OPTIC_WAVE'),
        ('OPTIC_SPEC', 'OPTIC_SPEC'),
        ('OPTIC_EYE', 'OPTIC_EYE'),
        ('OPTIC_MOD', 'OPTIC_MOD'),
        ('OPTIC_EXT', 'OPTIC_EXT'),
        ('OPTIC_SENS', 'OPTIC_SENS'),
        ('OPTIC_RESP', 'OPTIC_RESP'),
        ('OPTIC_DARK', 'OPTIC_DARK'),
        ('OPTIC_PREWARMUP', 'OPTIC_PREWARMUP'),
        ('OPTIC_WARMUP', 'OPTIC_WARMUP'),
        ('OPTICAL_ANSI', 'OPTIC_ANSI'),
        ('OPTICAL_IEC', 'OPTIC_IEC'),
        ('OPTICAL_POWER', 'OPTIC_POWER'),

        # FUNC/FUNCTIONAL subgroups
        ('FUNC_BIST', 'FUNC_BIST'),
        ('FUNC_SCAN', 'FUNC_SCAN'),
        ('FUNC_MBIST', 'FUNC_MBIST'),
        ('FUNC_LBIST', 'FUNC_LBIST'),
        ('FUNC_JTAG', 'FUNC_JTAG'),
        ('FUNC_GPIO', 'FUNC_GPIO'),
        ('FUNC_SPI', 'FUNC_SPI'),
        ('FUNC_I2C', 'FUNC_I2C'),
        ('FUNC_I3C', 'FUNC_I3C'),
        ('FUNC_UART', 'FUNC_UART'),
        ('FUNC_MEM', 'FUNC_MEM'),
        ('FUNC_LOGIC', 'FUNC_LOGIC'),
        ('FUNCTIONAL_BIST', 'FUNC_BIST'),
        ('FUNCTIONAL_SCAN', 'FUNC_SCAN'),

        # EFUSE subgroups
        ('EFUSE_PROG', 'EFUSE_PROG'),
        ('EFUSE_READ', 'EFUSE_READ'),
        ('EFUSE_VERIFY', 'EFUSE_VERIFY'),
        ('EFUSE_TRIM', 'EFUSE_TRIM'),

        # INIT/INITIALIZE subgroups
        ('INIT_POWER', 'INIT_POWER'),
        ('INIT_RESET', 'INIT_RESET'),
        ('INIT_CONFIG', 'INIT_CONFIG'),
        ('INITIALIZE_POWER', 'INIT_POWER'),
        ('INITIALIZE_RESET', 'INIT_RESET'),

        # DIGITAL subgroups
        ('DIGITAL_IO', 'DIGITAL_IO'),
        ('DIGITAL_TIMING', 'DIGITAL_TIMING'),
        ('DIGITAL_FREQ', 'DIGITAL_FREQ'),
        ('DIGITAL_CLK', 'DIGITAL_CLK'),

        # POWER subgroups
        ('POWER_SUPPLY', 'POWER_SUPPLY'),
        ('POWER_RAIL', 'POWER_RAIL'),
        ('POWER_CONS', 'POWER_CONS'),

        # TEST subgroups
        ('TEST_SETUP', 'TEST_SETUP'),
        ('TEST_MEAS', 'TEST_MEAS'),
    ]

    # First, check for detailed patterns (longer patterns first = more specific)
    for pattern, group in sorted(detailed_patterns, key=lambda x: -len(x[0])):
        if pattern in col_str:
            return group

    # Fallback: Check for underscore-separated prefix with second level
    if '_' in col_str:
        parts = col_str.split('_')
        if len(parts) >= 2:
            # Try to create a two-level group name
            first_part = parts[0]
            second_part = parts[1]

            # Known main groups
            main_groups = ['DC', 'ANLG', 'ANALOG', 'OPTIC', 'OPTICAL', 'FUNC', 'FUNCTIONAL',
                           'EFUSE', 'INIT', 'INITIALIZE', 'DIGITAL', 'POWER', 'TEST', 'MEAS']

            if first_part in main_groups:
                # Normalize main group name
                normalized_main = {
                    'ANALOG': 'ANLG',
                    'OPTICAL': 'OPTIC',
                    'FUNCTIONAL': 'FUNC',
                    'INITIALIZE': 'INIT'
                }.get(first_part, first_part)

                # Create subgroup if second part is meaningful (not just numbers)
                if len(second_part) >= 2 and not second_part.isdigit():
                    # Truncate very long subgroup names
                    subgroup = second_part[:10] if len(second_part) > 10 else second_part
                    return f"{normalized_main}_{subgroup}".title()
                else:
                    return normalized_main.title()

            # If first part is short enough, use it as group
            if len(first_part) >= 2 and len(first_part) <= 10:
                return first_part.title()

    # Fallback: Check for known prefixes at start
    prefixes = ['OPTIC', 'OPTICAL', 'DC', 'ELECTRICAL', 'ANALOG', 'ANLG', 'DIGITAL',
               'POWER', 'SIGNAL', 'TEST', 'MEAS', 'PARAM', 'FUNC', 'EFUSE', 'INIT']

    for prefix in prefixes:
        if col_str.startswith(prefix):
            return prefix.title()

    return "Other"  # Default group


def convert_am_data_column_name(col_name):
    """
    Konvertiert AM DATA Spaltennamen zum lesbaren Format - DYNAMISCH, nicht hardcodiert!

    Funktionen:
    1. Gruppen-Präfix DYNAMISCH erkennen und entfernen (Pattern: XXXX_YYYY- am Anfang)
    2. ALLE kodierten Werte automatisch konvertieren:
       - FV0P1 → 0.1V (Force Voltage)
       - FC0P2, FCn0P2 → 0.2mA, -0.2mA (Force Current)
       - AVEEn1p8 → -1.80V
       - DACI3p0, DACIn0p6 → 3.00uA, -0.60uA
       - DC4p59 → 4.59%
       - XpY Pattern → X.Y (generisch für alle Werte)
    """
    import re

    # Wenn kein <> Trenner, original zurückgeben
    if ' <> ' not in col_name:
        return col_name

    # Teil nach <> extrahieren (enthält die echten Werte)
    parts = col_name.split(' <> ')
    if len(parts) != 2:
        return col_name

    long_name = parts[1].strip()

    # Whitespace bereinigen - LEERZEICHEN ENTFERNEN (nicht durch _ ersetzen!)
    long_name = re.sub(r'\s+', '', long_name)

    # ============================================================
    # 1. GRUPPEN-PRÄFIX DYNAMISCH ENTFERNEN
    # ============================================================
    # Pattern: Alles am Anfang bis zum ersten Subtest-Indikator
    # Typische Subtest-Start-Wörter: LOW, HIGH, STATIC, SINK, SOURCE, PREWARMUP, POSTWARMUP, etc.
    # Oder: GRUPPE_SUBGRUPPE- (z.B. OPTIC_ANSI-, ANLG_DISPLAYI-)

    # Pattern 1: XXXX_YYYY- oder XXXX_YYYY_ am Anfang (z.B. OPTIC_ANSI-, DC_SHORT_)
    prefix_match = re.match(r'^([A-Z]+_[A-Z0-9]+[-_])', long_name, re.IGNORECASE)
    if prefix_match:
        long_name = long_name[len(prefix_match.group(1)):]

    # ============================================================
    # 2. KODIERTE WERTE DYNAMISCH KONVERTIEREN
    # ============================================================

    # FV (Force Voltage): FV0P1 → 0.1V, FV1P8 → 1.8V
    def convert_fv(match):
        integer = match.group(1)
        decimal = match.group(2)
        return f"{integer}.{decimal}V"
    long_name = re.sub(r'FV(\d+)P(\d+)', convert_fv, long_name, flags=re.IGNORECASE)

    # FC (Force Current): FC0P2 → 0.2mA, FCn0P2 → -0.2mA
    def convert_fc(match):
        sign = '-' if match.group(1).lower() == 'n' else ''
        integer = match.group(2)
        decimal = match.group(3)
        return f"{sign}{integer}.{decimal}mA"
    long_name = re.sub(r'FC([np]?)(\d+)P(\d+)', convert_fc, long_name, flags=re.IGNORECASE)

    # AVEE (Voltage): AVEEn1p8 → -1.80V, AVEE1p8 → 1.80V
    def convert_avee(match):
        sign = '-' if match.group(1).lower() == 'n' else ''
        integer = match.group(2)
        decimal = match.group(3).ljust(2, '0')  # Mindestens 2 Dezimalstellen
        return f"{sign}{integer}.{decimal}V"
    long_name = re.sub(r'AVEE([np]?)(\d+)p(\d+)', convert_avee, long_name, flags=re.IGNORECASE)

    # DACI (Current): DACI3p0 → 3.00uA, DACIn0p6 → -0.60uA
    def convert_daci(match):
        sign = '-' if match.group(1).lower() == 'n' else ''
        integer = match.group(2)
        decimal = match.group(3).ljust(2, '0')  # Mindestens 2 Dezimalstellen
        return f"{sign}{integer}.{decimal}uA"
    long_name = re.sub(r'DACI([np]?)(\d+)p(\d+)', convert_daci, long_name, flags=re.IGNORECASE)

    # DC (Duty Cycle): DC4p59 → 4.59%
    def convert_dc(match):
        integer = match.group(1)
        decimal = match.group(2)
        return f"{integer}.{decimal}%"
    long_name = re.sub(r'(?<![A-Z])DC(\d+)p(\d+)', convert_dc, long_name, flags=re.IGNORECASE)

    # ============================================================
    # 3. CLEANUP
    # ============================================================

    # Entferne FREERUN_X_, INTFRAME_X_, etc. (Test-Modi die nicht wichtig sind)
    long_name = re.sub(r'_?(FREERUN|INTFRAME)_X_', '_', long_name, flags=re.IGNORECASE)

    # Doppelte Unterstriche entfernen
    long_name = re.sub(r'_+', '_', long_name)

    # Führende/trailing Unterstriche entfernen
    long_name = long_name.strip('_')

    return long_name


# ============================================================================
# MC-300 LOADER (STANDALONE - Modular, berührt CSV/STDF nicht)
# ============================================================================
def load_mc300_file():
    """
    Load wafermap data from MC-300 format file (ASAP MC-300 Prober).

    STANDALONE FUNKTION - Berührt CSV/STDF Routinen NICHT.

    MC-300 Format:
    - Zeile 1-15: Header (Typ, Datum, Wafer-ID, etc.)
    - Zeile 11: Anzahl Dies
    - Zeile 16: Anzahl Parameter
    - Zeile 17+: Parameter-Definitionen
    - Danach: Messdaten
    """
    global current_stdf_data, current_wafer_id, test_parameters, grouped_parameters, test_limits
    global multiple_stdf_data, multiple_wafer_ids

    file_path = filedialog.askopenfilename(
        title="Select MC-300 file",
        filetypes=[("Text files", "*.txt"), ("All files", "*.*")],
    )

    if not file_path:
        return

    print(f"Loading MC-300 file: {file_path}")

    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            lines = f.readlines()

        # Parse Header (Zeile 1-15)
        header_info = {
            'type': lines[0].strip() if len(lines) > 0 else '',
            'datetime_device': lines[1].strip() if len(lines) > 1 else '',
            'wafer_id': lines[2].strip() if len(lines) > 2 else '',
            'version': lines[5].strip() if len(lines) > 5 else '',
            'production_site': lines[6].strip() if len(lines) > 6 else '',
            'recipe': lines[7].strip() if len(lines) > 7 else '',
            'num_dies': int(lines[10].strip()) if len(lines) > 10 else 0,
            'num_params': int(lines[15].strip()) if len(lines) > 15 else 0
        }

        print(f"MC-300 Header: Wafer={header_info['wafer_id']}, Dies={header_info['num_dies']}, Params={header_info['num_params']}")

        # Parse Parameter-Definitionen (ab Zeile 17)
        param_start_line = 16
        param_definitions = []

        for i in range(header_info['num_params']):
            if param_start_line + i < len(lines):
                line = lines[param_start_line + i].strip()
                parts = line.split()
                if len(parts) >= 2:
                    param_definitions.append({
                        'id': parts[0],
                        'name': parts[1],
                        'unit': parts[2] if len(parts) > 2 and parts[2] != '-' else '',
                        'condition': parts[3] if len(parts) > 3 and parts[3] != '-' else ''
                    })

        print(f"Parsed {len(param_definitions)} parameter definitions")

        # Parse Messdaten
        data_start_line = param_start_line + header_info['num_params']
        die_data = []

        for i in range(header_info['num_dies']):
            if data_start_line + i < len(lines):
                line = lines[data_start_line + i].strip()
                values = line.split()
                if len(values) >= header_info['num_params']:
                    float_values = []
                    for v in values[:header_info['num_params']]:
                        try:
                            float_values.append(float(v))
                        except ValueError:
                            float_values.append(0.0)

                    bin_value = int(float(values[-1])) if len(values) > header_info['num_params'] else 1
                    die_data.append({'values': float_values, 'bin': bin_value})

        print(f"Parsed {len(die_data)} die measurements")

        # Erstelle DataFrame
        x_idx, y_idx = 0, 1

        data_dict = {
            'x': [int(d['values'][x_idx]) for d in die_data],
            'y': [int(d['values'][y_idx]) for d in die_data],
            'bin': [d['bin'] for d in die_data],
        }

        # Füge Messparameter hinzu (ab Index 2)
        for i, param in enumerate(param_definitions):
            if i >= 2:
                col_name = param['name']
                if param['unit']:
                    col_name += f"_{param['unit']}"
                if param['condition']:
                    col_name += f"_{param['condition']}"
                data_dict[col_name] = [d['values'][i] for d in die_data]

        df = pd.DataFrame(data_dict)
        print(f"MC-300 DataFrame: {len(df)} rows, {len(df.columns)} columns")
        print(f"X range: {df['x'].min()}-{df['x'].max()}, Y range: {df['y'].min()}-{df['y'].max()}")

        # Setze globale Variablen
        current_wafer_id = header_info['wafer_id']
        current_stdf_data = df

        # Füge zu Multiple Wafers hinzu
        multiple_stdf_data.append(df)
        multiple_wafer_ids.append(current_wafer_id)

        # Baue test_parameters und grouped_parameters für MC-300
        test_parameters.clear()
        grouped_parameters.clear()
        test_limits.clear()

        mc300_group = f"MC300_{header_info['recipe']}"
        grouped_parameters[mc300_group] = []

        param_num = 1
        for i, param in enumerate(param_definitions):
            if i >= 2:
                col_name = param['name']
                if param['unit']:
                    col_name += f"_{param['unit']}"
                if param['condition']:
                    col_name += f"_{param['condition']}"

                test_key = f"test_{param_num}"
                test_parameters[test_key] = col_name
                grouped_parameters[mc300_group].append((param_num, col_name, col_name))
                param_num += 1

        print(f"MC-300: {len(test_parameters)} parameters in group '{mc300_group}'")

        # Update UI
        update_wafer_tab_selection_list()
        update_group_combobox()
        on_group_selected()
        update_charac_params()  # Charac-Curve Parameter-Listen aktualisieren
        refresh_heatmap_display()

        print(f"Successfully loaded MC-300: {header_info['wafer_id']}")
        messagebox.showinfo("Success", f"Loaded MC-300:\n{header_info['wafer_id']}\n{len(die_data)} dies, {param_num-1} parameters")

    except Exception as e:
        print(f"Error loading MC-300: {e}")
        import traceback
        traceback.print_exc()
        messagebox.showerror("Error", f"Failed to load MC-300:\n{str(e)}")


def load_csv_wafermap_file():
    """Load wafermap data from a CSV file"""
    global current_stdf_data, current_wafer_id, test_parameters, grouped_parameters, test_limits
    global multiple_stdf_data, multiple_wafer_ids, die_image_directory

    csv_path = filedialog.askopenfilename(
        title="Select a CSV file with wafermap data",
        filetypes=[("CSV files", "*.csv"), ("All files", "*.*")],
    )

    if not csv_path:
        return

    try:
        print(f"Loading CSV file: {csv_path}")

        # Read CSV file
        df = pd.read_csv(csv_path)

        # Check for required columns (x, y coordinates)
        # Common column names for coordinates
        x_col_candidates = ['x', 'X', 'x_coord', 'X_COORD', 'X_Coordinate', 'x_coordinate', 'DIE_X', 'die_x', 'col', 'COL', 'Column']
        y_col_candidates = ['y', 'Y', 'y_coord', 'Y_COORD', 'Y_Coordinate', 'y_coordinate', 'DIE_Y', 'die_y', 'row', 'ROW', 'Row']

        x_col = None
        y_col = None

        for candidate in x_col_candidates:
            if candidate in df.columns:
                x_col = candidate
                break

        for candidate in y_col_candidates:
            if candidate in df.columns:
                y_col = candidate
                break

        if x_col is None or y_col is None:
            # If standard names not found, try to guess from first few columns
            print(f"Warning: Could not find standard x/y columns. Available columns: {df.columns.tolist()}")
            # Try to prompt user or use first two numeric columns
            numeric_cols = df.select_dtypes(include=[np.number]).columns.tolist()
            if len(numeric_cols) >= 2:
                x_col = numeric_cols[0]
                y_col = numeric_cols[1]
                print(f"Using '{x_col}' as X coordinate and '{y_col}' as Y coordinate")
            else:
                print("ERROR: Could not identify coordinate columns in CSV")
                return

        # Standardize column names
        df = df.rename(columns={x_col: 'x', y_col: 'y'})

        # Look for bin column - WICHTIG: HardBin und SoftBin müssen zuerst kommen!
        bin_col_candidates = ['HardBin', 'SoftBin', 'hardbin', 'softbin', 'bin', 'BIN', 'Bin', 'HARD_BIN', 'hard_bin', 'SOFT_BIN', 'soft_bin', 'HB', 'SB']
        bin_col = None
        for candidate in bin_col_candidates:
            if candidate in df.columns:
                bin_col = candidate
                df = df.rename(columns={bin_col: 'bin'})
                break

        if 'bin' not in df.columns:
            # Create a default bin column (all pass = bin 1)
            df['bin'] = 1
            print("No bin column found, created default bin column (all bins = 1)")

        # Extract wafer ID from filename
        wafer_id = os.path.basename(csv_path).replace('.csv', '').replace('.CSV', '')

        # Build test parameters from remaining numeric columns
        test_params = {}
        grouped_params = {}  # Will be populated with detected groups
        test_limits_dict = {}

        numeric_columns = df.select_dtypes(include=[np.number]).columns.tolist()
        # Exclude x, y, bin from parameter list
        exclude_cols = ['x', 'y', 'bin']
        test_columns = [col for col in numeric_columns if col not in exclude_cols]

        # Use global extract_group_from_column function for grouping
        import re
        for idx, col in enumerate(test_columns):
            # Convert AM DATA format to RED WAFER format for display
            display_name = convert_am_data_column_name(col)

            # For group extraction, use the SHORT NAME (before <>) - this has the correct group structure
            # e.g., "OPTIC_ANSI-PREWARMUP_VTHERM0_..." -> Group: "OPTIC_ANSI"
            if ' <> ' in col:
                group_source = col.split(' <> ')[0].strip()  # Use SHORT name (before <>)
            else:
                group_source = col

            # Clean up any whitespace in group_source (CSV sometimes has line breaks)
            group_source = re.sub(r'\s+', '_', group_source)  # Replace spaces with underscores

            # Try to extract test number from column name (e.g., "DC_SHORT_LOW_VDD10_..._10020001")
            # Look for a number at the end of the column name (use display_name or original)
            match = re.search(r'_(\d{5,})$', str(display_name)) or re.search(r'_(\d{5,})$', str(col))
            if match:
                test_num = int(match.group(1))
            else:
                # Fallback to sequential numbering
                test_num = idx + 1

            test_key = f"test_{test_num}"

            # Detect group from SHORT column name (preserves OPTIC_ANSI etc.)
            group_name = extract_group_from_column(group_source)

            # Rename column to match expected format (use test number as column name)
            df = df.rename(columns={col: test_num})

            test_params[test_key] = display_name  # Use converted display name

            # Add to appropriate group
            if group_name not in grouped_params:
                grouped_params[group_name] = []
            grouped_params[group_name].append((test_num, display_name, display_name))

            # Calculate limits from data (min/max)
            col_data = df[test_num].dropna()
            if len(col_data) > 0:
                test_limits_dict[test_num] = {
                    'lo_limit': col_data.min(),
                    'hi_limit': col_data.max(),
                    'units': ''
                }

        # Print detected groups
        print(f"Detected groups from CSV: {list(grouped_params.keys())}")
        for grp, params in grouped_params.items():
            print(f"  {grp}: {len(params)} parameters")

        # Store HardBin/SoftBin column names for later use in heatmap
        global hardbin_column, softbin_column
        hardbin_column = None
        softbin_column = None

        for col in df.columns:
            col_lower = str(col).lower()
            if col_lower in ['hardbin', 'hbin', 'hard_bin']:
                hardbin_column = col
                print(f"  Found HardBin column: '{col}'")
            elif col_lower in ['softbin', 'sbin', 'soft_bin']:
                softbin_column = col
                print(f"  Found SoftBin column: '{col}'")

        # Update global variables
        current_stdf_data = df
        current_wafer_id = wafer_id
        test_parameters = test_params
        grouped_parameters = grouped_params
        test_limits = test_limits_dict

        # Also update multiple_stdf_data - APPEND to allow multi-wafer loading
        if not multiple_stdf_data:
            multiple_stdf_data = [df]
            multiple_wafer_ids = [wafer_id]
        else:
            # Check if this wafer is already loaded (by ID)
            if wafer_id not in multiple_wafer_ids:
                multiple_stdf_data.append(df)
                multiple_wafer_ids.append(wafer_id)
            else:
                # Replace existing wafer data
                idx = multiple_wafer_ids.index(wafer_id)
                multiple_stdf_data[idx] = df

        # Try to detect notch orientation from CSV columns or data
        global current_wafer_config
        notch_orientation = None

        # Check for notch/flat column in CSV
        notch_col_candidates = ['notch', 'Notch', 'NOTCH', 'flat', 'Flat', 'FLAT',
                                'WF_FLAT', 'wf_flat', 'orientation', 'Orientation',
                                'ORIENTATION', 'wafer_flat', 'WAFER_FLAT']

        for candidate in notch_col_candidates:
            if candidate in df.columns:
                # Get the first non-null value
                notch_values = df[candidate].dropna()
                if len(notch_values) > 0:
                    notch_val = str(notch_values.iloc[0]).strip().upper()
                    # Map common values to standard U/D/L/R
                    notch_mapping = {
                        'U': 'U', 'UP': 'U', '0': 'U', 'TOP': 'U', 'NORTH': 'U',
                        'D': 'D', 'DOWN': 'D', '180': 'D', 'BOTTOM': 'D', 'SOUTH': 'D',
                        'L': 'L', 'LEFT': 'L', '270': 'L', 'WEST': 'L',
                        'R': 'R', 'RIGHT': 'R', '90': 'R', 'EAST': 'R'
                    }
                    notch_orientation = notch_mapping.get(notch_val, notch_val[0] if notch_val else None)
                    print(f"Detected notch orientation from CSV column '{candidate}': {notch_orientation}")
                break

        # If not found in columns, check in the original CSV for header comments or metadata
        if notch_orientation is None:
            try:
                with open(csv_path, 'r') as f:
                    # Read first 20 lines to look for notch info in comments
                    for i, line in enumerate(f):
                        if i > 20:
                            break
                        line_upper = line.upper()
                        if 'NOTCH' in line_upper or 'FLAT' in line_upper:
                            # Try to extract orientation
                            for orient in ['UP', 'DOWN', 'LEFT', 'RIGHT', 'NORTH', 'SOUTH', 'EAST', 'WEST']:
                                if orient in line_upper:
                                    notch_mapping = {'UP': 'U', 'DOWN': 'D', 'LEFT': 'L', 'RIGHT': 'R',
                                                    'NORTH': 'U', 'SOUTH': 'D', 'WEST': 'L', 'EAST': 'R'}
                                    notch_orientation = notch_mapping.get(orient, 'D')
                                    print(f"Detected notch orientation from CSV header: {notch_orientation}")
                                    break
                            if notch_orientation:
                                break
            except:
                pass

        # Default to 'D' (down) if not found - common default
        if notch_orientation is None:
            notch_orientation = 'D'
            print(f"No notch orientation found in CSV, using default: {notch_orientation}")

        # Update wafer config
        current_wafer_config = {
            'notch_orientation': notch_orientation,
            'wafer_size': None,
            'die_width': None,
            'die_height': None,
            'pos_x': None,
            'pos_y': None
        }
        print(f"Wafer config set: Notch={current_wafer_config.get('notch_orientation')}")

        # Try to auto-detect image folder from CSV path
        # Look for ImageCaptures folder in parent or sibling directories
        csv_dir = os.path.dirname(csv_path)
        parent_dir = os.path.dirname(csv_dir)

        possible_image_dirs = [
            os.path.join(parent_dir, "ImageCaptures"),
            os.path.join(parent_dir, "Images"),
            os.path.join(csv_dir, "ImageCaptures"),
            os.path.join(csv_dir, "Images"),
        ]

        for img_dir in possible_image_dirs:
            if os.path.isdir(img_dir):
                die_image_directory = img_dir
                short_path = os.path.basename(img_dir)
                folder_status_label.config(text=f"Img: {short_path}", fg="green")
                print(f"Auto-detected image folder: {img_dir}")
                break
        else:
            print("No image folder auto-detected. Use 'Image Folder' button to select manually.")

        # Auto-detect PLM folder from CSV path
        global plm_file_directory
        possible_plm_dirs = [
            os.path.join(parent_dir, "PLMFiles"),
            os.path.join(parent_dir, "PLM"),
            os.path.join(csv_dir, "PLMFiles"),
            os.path.join(csv_dir, "PLM"),
        ]

        for plm_dir in possible_plm_dirs:
            if os.path.isdir(plm_dir):
                plm_file_directory = plm_dir
                print(f"Auto-detected PLM folder: {plm_dir}")
                # Update folder status
                current_status = folder_status_label.cget("text")
                if current_status and "Img:" in current_status:
                    folder_status_label.config(text=f"{current_status} | PLM:✓", fg="green")
                else:
                    folder_status_label.config(text=f"PLM:✓", fg="green")
                break
        else:
            print("No PLM folder auto-detected.")

        print(f"Loaded CSV with {len(df)} dies and {len(test_params)} parameters")
        print(f"Wafer ID: {wafer_id}")
        print(f"Parameters: {list(test_params.values())[:10]}...")  # Show first 10

        # Update UI
        update_group_combobox()

        # Build param options with HardBin/SoftBin first (as default)
        param_options = []
        if hardbin_column:
            param_options.append("HardBin")
        if softbin_column:
            param_options.append("SoftBin")
        if not param_options:
            param_options.append("BIN (Bin Number)")

        for test_key, test_name in sorted(test_parameters.items()):
            param_options.append(f"{test_key}: {test_name}")

        heatmap_param_combobox["values"] = param_options
        if param_options:
            heatmap_param_combobox.current(0)  # Default to first item (HardBin)

        # Update Charac.-Curve dropdowns
        update_charac_params()

        # Update heatmap display
        refresh_heatmap_display()
        update_heatmap_parameter_list()

        # Update info label
        heatmap_info_label.config(text=f"Loaded: {wafer_id} ({len(df)} dies)")

    except Exception as e:
        print(f"Error loading CSV file: {e}")
        import traceback
        traceback.print_exc()


def read_wafermap_from_stdf(stdf_path):
    """
    Read wafermap data from STDF file.
    OPTIMIZED version with debug output for troubleshooting.
    Now also reads WCR (Wafer Configuration Record) for notch orientation.
    """
    import re

    # Pre-compile regex patterns (performance optimization)
    PATTERN_SECTION = re.compile(r'^>{3,}\s*(.+?)\s*<{3,}$')
    PATTERN_SUBGROUP = re.compile(r'^<([A-Za-z][A-Za-z0-9_]*)>$')
    PATTERN_BRACKET = re.compile(r'^\[([A-Za-z][A-Za-z0-9_]*)\]$')
    EXCLUDED_GROUPS = {"Definitions", "Initialization"}

    wafermap = []
    wafer_id = None
    test_params = {}
    test_groups = {}
    grouped_params = {}
    test_limits_dict = {}

    # Wafer configuration from WCR record
    wafer_config = {
        'notch_orientation': None,
        'wafer_size': None,
        'die_width': None,
        'die_height': None,
        'pos_x': None,
        'pos_y': None
    }

    if STDF_MODULE is None:
        print("ERROR: STDF library not installed! Install with: pip install Semi-ATE-STDF")
        return pd.DataFrame(), None, {}, {}, {}, wafer_config

    try:
        if STDF_TYPE == "pystdf":
            wafermap, wafer_id, test_params, grouped_params, test_limits_dict, wafer_config = read_with_pystdf(stdf_path)
        else:
            file_size = os.path.getsize(stdf_path)
            print(f"Loading: {os.path.basename(stdf_path)} ({file_size / 1024 / 1024:.1f} MB)...")
            load_start = time.time()

            test_info = {}
            current_die_tests = {}
            current_group = "Ungrouped"
            wafermap = []
            debug_prr_printed = False
            debug_wcr_printed = False

            with open(stdf_path, "rb") as f:
                records_gen = STDF_MODULE.records_from_file(f)
                record_count = 0
                prr_count = 0
                last_update = time.time()

                for record in records_gen:
                    record_count += 1

                    # Progress update every 2 seconds
                    if record_count % 100000 == 0:
                        now = time.time()
                        if now - last_update > 2.0:
                            elapsed = now - load_start
                            print(f"  {record_count:,} records, {len(wafermap):,} dies ({elapsed:.0f}s)...")
                            last_update = now

                    rec_type = type(record).__name__

                    # WCR - Wafer Configuration Record
                    if rec_type == "WCR":
                        try:
                            # Debug: Print all available fields in WCR record
                            if not debug_wcr_printed:
                                print(f"  DEBUG WCR Record found!")
                                print(f"    Type: {type(record)}")
                                print(f"    Dir: {[a for a in dir(record) if not a.startswith('_')]}")
                                if hasattr(record, "get_value"):
                                    # Try to get all possible field names
                                    for field_name in ['WF_FLAT', 'WAFR_SIZ', 'DIE_WID', 'DIE_HT', 'POS_X', 'POS_Y', 'CENTER_X', 'CENTER_Y']:
                                        try:
                                            val = record.get_value(field_name)
                                            print(f"    {field_name}: {val} (type: {type(val).__name__})")
                                        except:
                                            print(f"    {field_name}: <not available>")

                            if hasattr(record, "get_value"):
                                wafer_config['notch_orientation'] = record.get_value("WF_FLAT")
                                wafer_config['wafer_size'] = record.get_value("WAFR_SIZ")
                                wafer_config['die_width'] = record.get_value("DIE_WID")
                                wafer_config['die_height'] = record.get_value("DIE_HT")
                                wafer_config['pos_x'] = record.get_value("POS_X")
                                wafer_config['pos_y'] = record.get_value("POS_Y")
                            elif hasattr(record, "WF_FLAT"):
                                wafer_config['notch_orientation'] = record.WF_FLAT
                                wafer_config['wafer_size'] = getattr(record, 'WAFR_SIZ', None)
                                wafer_config['die_width'] = getattr(record, 'DIE_WID', None)
                                wafer_config['die_height'] = getattr(record, 'DIE_HT', None)
                                wafer_config['pos_x'] = getattr(record, 'POS_X', None)
                                wafer_config['pos_y'] = getattr(record, 'POS_Y', None)

                            if not debug_wcr_printed:
                                print(f"  WCR Result: Notch='{wafer_config['notch_orientation']}', Size={wafer_config['wafer_size']}mm")
                                debug_wcr_printed = True
                        except Exception as e:
                            if not debug_wcr_printed:
                                print(f"  DEBUG WCR error: {e}")
                                import traceback
                                traceback.print_exc()
                                debug_wcr_printed = True

                    elif rec_type == "PRR":
                        prr_count += 1
                        try:
                            # Try different methods to access record fields
                            x_coord = None
                            y_coord = None
                            hard_bin = None
                            soft_bin = None

                            # Method 1: get_value method (Semi_ATE.STDF uses this)
                            if hasattr(record, "get_value"):
                                x_coord = record.get_value("X_COORD")
                                y_coord = record.get_value("Y_COORD")
                                hard_bin = record.get_value("HARD_BIN")
                                soft_bin = record.get_value("SOFT_BIN")
                            # Method 2: fields dict
                            elif hasattr(record, "fields"):
                                fields = record.fields
                                x_coord = fields.get("X_COORD")
                                y_coord = fields.get("Y_COORD")
                                hard_bin = fields.get("HARD_BIN")
                                soft_bin = fields.get("SOFT_BIN")
                            # Method 3: Direct attribute access
                            elif hasattr(record, "X_COORD"):
                                x_coord = record.X_COORD
                                y_coord = record.Y_COORD if hasattr(record, "Y_COORD") else None
                                hard_bin = record.HARD_BIN if hasattr(record, "HARD_BIN") else None
                                soft_bin = record.SOFT_BIN if hasattr(record, "SOFT_BIN") else None

                            # Debug: Print first PRR record structure
                            if not debug_prr_printed:
                                print(f"  DEBUG PRR: type={type(record)}, dir={[a for a in dir(record) if not a.startswith('_')][:15]}")
                                if hasattr(record, "__dict__"):
                                    print(f"  DEBUG PRR __dict__: {list(record.__dict__.keys())[:10]}")
                                print(f"  DEBUG PRR values: x={x_coord}, y={y_coord}, hbin={hard_bin}, sbin={soft_bin}")
                                debug_prr_printed = True

                            if x_coord is not None and y_coord is not None:
                                die_data = {
                                    "x": x_coord,
                                    "y": y_coord,
                                    "bin": hard_bin if hard_bin is not None else soft_bin,
                                }
                                if current_die_tests:
                                    die_data.update(current_die_tests)
                                wafermap.append(die_data)
                        except Exception as e:
                            if not debug_prr_printed:
                                print(f"  DEBUG PRR error: {e}")
                                debug_prr_printed = True

                    elif rec_type == "PTR":
                        try:
                            # Try different access methods
                            test_num = None
                            if hasattr(record, "TEST_NUM"):
                                test_num = record.TEST_NUM
                            elif hasattr(record, "get_value"):
                                test_num = record.get_value("TEST_NUM")

                            if test_num is not None:
                                result = None
                                if hasattr(record, "RESULT"):
                                    result = record.RESULT
                                elif hasattr(record, "get_value"):
                                    result = record.get_value("RESULT")

                                if test_num not in test_info:
                                    test_name = None
                                    if hasattr(record, "TEST_TXT"):
                                        test_name = record.TEST_TXT
                                    elif hasattr(record, "get_value"):
                                        test_name = record.get_value("TEST_TXT")
                                    if test_name:
                                        test_info[test_num] = test_name
                                        test_groups[test_num] = current_group

                                if test_num not in test_limits_dict:
                                    lo_limit = getattr(record, "LO_LIMIT", None) or (record.get_value("LO_LIMIT") if hasattr(record, "get_value") else None)
                                    hi_limit = getattr(record, "HI_LIMIT", None) or (record.get_value("HI_LIMIT") if hasattr(record, "get_value") else None)
                                    units = getattr(record, "UNITS", "") or (record.get_value("UNITS") if hasattr(record, "get_value") else "") or ""
                                    test_limits_dict[test_num] = {
                                        'lo_limit': lo_limit,
                                        'hi_limit': hi_limit,
                                        'units': units
                                    }

                                if result is not None:
                                    current_die_tests[test_num] = result
                        except:
                            pass

                    elif rec_type == "PIR":
                        current_die_tests = {}

                    elif rec_type == "WIR":
                        try:
                            if hasattr(record, "WAFER_ID"):
                                wafer_id = record.WAFER_ID
                            elif hasattr(record, "get_value"):
                                wafer_id = record.get_value("WAFER_ID")
                        except:
                            pass

                    elif rec_type == "DTR":
                        try:
                            text_data = None
                            if hasattr(record, "TEXT_DAT"):
                                text_data = record.TEXT_DAT
                            elif hasattr(record, "get_value"):
                                text_data = record.get_value("TEXT_DAT")

                            if text_data:
                                text_stripped = text_data.strip()
                                match = PATTERN_SECTION.match(text_stripped)
                                if match:
                                    group_name = match.group(1).strip()
                                    if group_name and group_name not in EXCLUDED_GROUPS:
                                        current_group = group_name
                                else:
                                    match = PATTERN_SUBGROUP.match(text_stripped)
                                    if match:
                                        current_group = match.group(1)
                                    else:
                                        match = PATTERN_BRACKET.match(text_stripped)
                                        if match:
                                            current_group = match.group(1)
                        except:
                            pass

                # Build test_params and grouped_params
                for test_num, test_name in test_info.items():
                    short_name = shorten_test_name(test_name) if test_name else f"Test {test_num}"
                    test_params[f"test_{test_num}"] = test_name  # Use full test name for display

                    # Use extract_group_from_column for consistent grouping (like CSV)
                    # This gives detailed subgroups like DC_LKG, DC_CONT, etc.
                    group = extract_group_from_column(test_name) if test_name else test_groups.get(test_num, "Ungrouped")

                    if group not in grouped_params:
                        grouped_params[group] = []
                    grouped_params[group].append((test_num, short_name, test_name))

                elapsed = time.time() - load_start
                print(f"  Done: {record_count:,} records | {len(wafermap):,} dies | {len(test_params)} params | {elapsed:.1f}s")

        df = pd.DataFrame(wafermap)
        if len(df) > 0:
            print(f"  Loaded: X[{df['x'].min()}-{df['x'].max()}] Y[{df['y'].min()}-{df['y'].max()}] Bins:{len(df['bin'].unique())}")

        return df, wafer_id, test_params, grouped_params, test_limits_dict, wafer_config

    except Exception as e:
        print(f"Error reading STDF: {e}")
        import traceback
        traceback.print_exc()
        return pd.DataFrame(), None, {}, {}, {}, wafer_config


def shorten_test_name(test_name):
    """Shorten test name by truncating at _X_X_X pattern"""
    if not test_name:
        return test_name

    import re
    # Find pattern like _X_X_X (where X can be any character or empty)
    # This matches _X_X_X, _X_X_X_, _X_X_X_something
    match = re.search(r'_X_X_X', test_name)
    if match:
        # Return everything before _X_X_X
        return test_name[:match.start()]

    # If no _X_X_X pattern, return original name (truncated if too long)
    if len(test_name) > 40:
        return test_name[:37] + "..."
    return test_name


def read_with_pystdf(stdf_path):
    import pystdf

    wafermap = []
    wafer_id = None
    test_params = {}
    test_info = {}
    current_die_tests = {}
    test_limits_dict = {}  # Dictionary to store test limits

    # Wafer configuration
    wafer_config = {
        'notch_orientation': None,
        'wafer_size': None,
        'die_width': None,
        'die_height': None,
        'pos_x': None,
        'pos_y': None
    }

    with open(stdf_path, "rb") as f:
        parser = pystdf.Parser(inp=f)

        for record in parser:
            if record.id == "WIR":
                wafer_id = record.WAFER_ID

            elif record.id == "WCR":
                try:
                    wafer_config['notch_orientation'] = getattr(record, 'WF_FLAT', None)
                    wafer_config['wafer_size'] = getattr(record, 'WAFR_SIZ', None)
                    wafer_config['die_width'] = getattr(record, 'DIE_WID', None)
                    wafer_config['die_height'] = getattr(record, 'DIE_HT', None)
                    wafer_config['pos_x'] = getattr(record, 'POS_X', None)
                    wafer_config['pos_y'] = getattr(record, 'POS_Y', None)
                    print(f"  WCR: Notch={wafer_config['notch_orientation']}, Size={wafer_config['wafer_size']}mm")
                except:
                    pass

            elif record.id == "PIR":
                current_die_tests = {}

            elif record.id == "PTR":
                try:
                    test_num = record.TEST_NUM
                    test_name = record.TEST_TXT
                    result = record.RESULT

                    if test_num is not None and test_name:
                        test_info[test_num] = test_name

                    # Extract test limits
                    if test_num is not None:
                        lo_limit = getattr(record, 'LO_LIMIT', None)
                        hi_limit = getattr(record, 'HI_LIMIT', None)
                        units = getattr(record, 'UNITS', "") or ""

                        if test_num not in test_limits_dict:
                            test_limits_dict[test_num] = {
                                'lo_limit': lo_limit,
                                'hi_limit': hi_limit,
                                'units': units
                            }
                        elif lo_limit is not None or hi_limit is not None:
                            if lo_limit is not None:
                                test_limits_dict[test_num]['lo_limit'] = lo_limit
                            if hi_limit is not None:
                                test_limits_dict[test_num]['hi_limit'] = hi_limit
                            if units:
                                test_limits_dict[test_num]['units'] = units

                    if test_num is not None and result is not None:
                        current_die_tests[test_num] = result

                except (ValueError, KeyError, AttributeError) as e:
                    print(f"Warning: Could not read PTR record: {e}")

            elif record.id == "PRR":
                try:
                    if record.X_COORD is not None and record.Y_COORD is not None:
                        die_data = {
                            "x": record.X_COORD,
                            "y": record.Y_COORD,
                            "bin": record.HARD_BIN
                            if record.HARD_BIN is not None
                            else record.SOFT_BIN,
                        }

                        for test_num in current_die_tests:
                            die_data[f"test_{test_num}"] = current_die_tests[test_num]

                        wafermap.append(die_data)

                except (ValueError, KeyError, AttributeError) as e:
                    print(f"Warning: Could not read PRR record: {e}")

    test_params = {f"test_{num}": shorten_test_name(name) for num, name in test_info.items()}

    # Create grouped_params (all in "Ungrouped" for pystdf since we don't parse DTR)
    grouped_params = {"Ungrouped": [(num, shorten_test_name(name), name) for num, name in test_info.items()]}

    return wafermap, wafer_id, test_params, grouped_params, test_limits_dict, wafer_config


def load_stdf_data(stdf_path):
    """Load STDF file and populate parameter selection"""
    global current_stdf_data, current_wafer_id, test_parameters, grouped_parameters, test_limits
    global current_wafer_config

    df, wafer_id, test_params, grouped_params, limits_dict, wafer_cfg = read_wafermap_from_stdf(stdf_path)

    current_stdf_data = df
    current_wafer_id = wafer_id
    test_parameters = test_params
    grouped_parameters = grouped_params
    test_limits = limits_dict
    current_wafer_config = wafer_cfg

    current_stdf_data = df
    current_wafer_id = wafer_id
    test_parameters = test_params
    grouped_parameters = grouped_params
    test_limits = limits_dict

    # Update group combobox
    update_group_combobox()

    param_options = ["BIN (Bin Number)"]
    for test_key, test_name in sorted(test_parameters.items()):
        param_options.append(f"{test_key}: {test_name}")

    param_combobox["values"] = param_options
    if param_options:
        param_combobox.current(0)

    print(f"Available parameters: {len(param_options)}")

    update_wafermap_with_parameter()
    update_heatmap_parameter_list()

    # Update Report tab group comboboxes
    try:
        update_pptx_report_group_combobox()
        print("Updated Report tab group comboboxes")
    except NameError:
        pass


def update_wafermap_with_parameter():
    """Update wafermap display based on selected parameter"""
    global current_stdf_data, current_wafer_id

    if current_stdf_data is None or current_stdf_data.empty:
        print("No STDF data loaded")
        return

    selected = param_combobox.get()
    print(f"\n=== Parameter Selection Debug ===")
    print(f"Selected from combobox: '{selected}'")

    if selected.startswith("BIN"):
        param_column = "bin"
        param_label = "Bin"
    else:
        # Extract test number from "test_XXXXX: Test Name" format
        test_key = selected.split(":")[0].strip()
        print(f"Extracted test_key: '{test_key}'")
        # Remove 'test_' prefix if present to get the actual column name
        if test_key.startswith("test_"):
            param_column = int(test_key.replace("test_", ""))
        else:
            param_column = int(test_key)
        param_label = selected
        print(f"Looking for column: {param_column} (type: {type(param_column).__name__})")

    print(f"Available columns (first 10): {list(current_stdf_data.columns[:10])}")
    print(f"Column types: {[type(col).__name__ for col in current_stdf_data.columns[:10]]}")

    update_wafermap_display(param_column, param_label)


def update_wafermap_display(parameter="bin", param_label="Bin"):
    """Display wafermap colored by specified parameter"""
    global wafermap_canvas, current_stdf_data, current_wafer_id

    fig, ax = plt.subplots(figsize=(10, 10))

    if current_stdf_data is not None and not current_stdf_data.empty:
        if parameter not in current_stdf_data.columns:
            ax.set_title(f"Parameter '{parameter}' not found in data")
            print(f"Available columns: {current_stdf_data.columns.tolist()}")
        else:
            plot_data = current_stdf_data.dropna(subset=[parameter])

            if len(plot_data) > 0:
                # Use custom bin colormap for bin values
                if parameter == "bin":
                    unique_bins = plot_data[parameter].unique()
                    cmap, norm = get_bin_colormap(unique_bins)
                else:
                    cmap = "viridis"
                    norm = None

                sc = ax.scatter(
                    plot_data["x"],
                    plot_data["y"],
                    c=plot_data[parameter],
                    cmap=cmap,
                    norm=norm,
                    s=80,
                    edgecolors="black",
                    linewidth=0.5,
                )

                ax.set_xlabel("X Coordinate", fontsize=12)
                ax.set_ylabel("Y Coordinate", fontsize=12)
                ax.set_title(
                    f"Wafermap for Wafer {current_wafer_id}\n{param_label}", fontsize=14
                )
                ax.grid(True, alpha=0.3)
                ax.set_aspect("equal")

                cbar = plt.colorbar(sc, ax=ax, label=param_label)
                cbar.ax.tick_params(labelsize=10)

                print(f"Plotted {len(plot_data)} dies with {parameter}")
                print(
                    f"Value range: {plot_data[parameter].min()} to {plot_data[parameter].max()}"
                )

            else:
                ax.set_title(f"No valid data for parameter '{param_label}'")
    else:
        ax.set_title("No wafermap data available")

    fig.tight_layout()

    if wafermap_canvas:
        wafermap_canvas.get_tk_widget().destroy()

    wafermap_canvas = FigureCanvasTkAgg(fig, master=wafermap_frame)
    wafermap_canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True, pady=10)
    wafermap_canvas.draw()
