def select_die_image_folder():
    """Select the folder containing die images"""
    global die_image_directory

    folder_path = filedialog.askdirectory(
        title="Select Image Folder for Die Images"
    )

    if folder_path:
        die_image_directory = folder_path
        # Show short version of path
        short_path = folder_path.split("/")[-1] if "/" in folder_path else folder_path.split("\\")[-1]
        folder_status_label.config(text=f"Img: {short_path}", fg="green")
        print(f"Die image folder set to: {folder_path}")


def show_image_gallery():
    """Show all images from the image folder in a gallery/grid view"""
    global die_image_directory

    if not die_image_directory:
        # Ask user to select folder first
        folder_path = filedialog.askdirectory(
            title="Select Image Folder to Display"
        )
        if not folder_path:
            return
        die_image_directory = folder_path
        short_path = folder_path.split("/")[-1] if "/" in folder_path else folder_path.split("\\")[-1]
        folder_status_label.config(text=f"Img: {short_path}", fg="green")

    # Get all image files
    image_extensions = ('.jpg', '.jpeg', '.png', '.gif', '.bmp', '.tif', '.tiff')
    image_files = []

    try:
        for filename in os.listdir(die_image_directory):
            if filename.lower().endswith(image_extensions):
                image_files.append(os.path.join(die_image_directory, filename))
    except Exception as e:
        print(f"Error reading image folder: {e}")
        return

    if not image_files:
        tk.messagebox.showinfo("No Images", f"No images found in:\n{die_image_directory}")
        return

    # Sort files by name
    image_files.sort()

    # Create gallery window
    gallery_win = tk.Toplevel(main_win)
    gallery_win.title(f"Image Gallery - {len(image_files)} images")
    gallery_win.geometry("1400x900")

    # Control frame at top
    control_frame = tk.Frame(gallery_win)
    control_frame.pack(side=tk.TOP, fill=tk.X, padx=10, pady=5)

    # Thumbnail size selector
    tk.Label(control_frame, text="Thumbnail Size:", font=("Helvetica", 10)).pack(side=tk.LEFT, padx=5)

    thumb_size_var = tk.StringVar(value="Medium")
    thumb_sizes = {"Small": 100, "Medium": 150, "Large": 200, "XLarge": 300}

    thumb_size_combo = ttk.Combobox(
        control_frame,
        textvariable=thumb_size_var,
        values=list(thumb_sizes.keys()),
        state="readonly",
        width=10
    )
    thumb_size_combo.pack(side=tk.LEFT, padx=5)

    # Columns selector
    tk.Label(control_frame, text="Columns:", font=("Helvetica", 10)).pack(side=tk.LEFT, padx=15)

    cols_var = tk.StringVar(value="Auto")
    cols_combo = ttk.Combobox(
        control_frame,
        textvariable=cols_var,
        values=["Auto", "2", "3", "4", "5", "6", "8", "10"],
        state="readonly",
        width=8
    )
    cols_combo.pack(side=tk.LEFT, padx=5)

    # Filter by die coordinates
    tk.Label(control_frame, text="Filter:", font=("Helvetica", 10)).pack(side=tk.LEFT, padx=15)

    filter_var = tk.StringVar(value="")
    filter_entry = tk.Entry(control_frame, textvariable=filter_var, width=20, font=("Helvetica", 10))
    filter_entry.pack(side=tk.LEFT, padx=5)

    # Info label
    info_label = tk.Label(control_frame, text=f"Total: {len(image_files)} images", font=("Helvetica", 10))
    info_label.pack(side=tk.RIGHT, padx=10)

    # Create scrollable canvas for thumbnails
    canvas_frame = tk.Frame(gallery_win)
    canvas_frame.pack(side=tk.TOP, fill=tk.BOTH, expand=True, padx=10, pady=5)

    gallery_canvas = tk.Canvas(canvas_frame, bg="#e0e0e0")
    scrollbar_y = tk.Scrollbar(canvas_frame, orient=tk.VERTICAL, command=gallery_canvas.yview)
    scrollbar_x = tk.Scrollbar(canvas_frame, orient=tk.HORIZONTAL, command=gallery_canvas.xview)

    scrollable_frame = tk.Frame(gallery_canvas, bg="#e0e0e0")

    scrollable_frame.bind(
        "<Configure>",
        lambda e: gallery_canvas.configure(scrollregion=gallery_canvas.bbox("all"))
    )

    gallery_canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
    gallery_canvas.configure(yscrollcommand=scrollbar_y.set, xscrollcommand=scrollbar_x.set)

    scrollbar_y.pack(side=tk.RIGHT, fill=tk.Y)
    scrollbar_x.pack(side=tk.BOTTOM, fill=tk.X)
    gallery_canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

    # Enable mousewheel scrolling
    def on_mousewheel(event):
        gallery_canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

    gallery_canvas.bind_all("<MouseWheel>", on_mousewheel)

    # Store image references to prevent garbage collection
    gallery_image_refs = []

    def load_thumbnails():
        """Load and display thumbnails"""
        nonlocal gallery_image_refs

        # Clear existing
        for widget in scrollable_frame.winfo_children():
            widget.destroy()
        gallery_image_refs.clear()

        # Get settings
        thumb_size = thumb_sizes.get(thumb_size_var.get(), 150)
        filter_text = filter_var.get().strip().lower()

        # Determine columns
        cols_setting = cols_var.get()
        if cols_setting == "Auto":
            # Calculate based on window width and thumbnail size
            try:
                win_width = gallery_win.winfo_width() - 50
                num_cols = max(2, win_width // (thumb_size + 20))
            except:
                num_cols = 5
        else:
            num_cols = int(cols_setting)

        # Filter images
        filtered_images = image_files
        if filter_text:
            filtered_images = [f for f in image_files if filter_text in os.path.basename(f).lower()]

        info_label.config(text=f"Showing: {len(filtered_images)} of {len(image_files)} images")

        # Create thumbnails
        row = 0
        col = 0

        for img_path in filtered_images:
            try:
                # Load and resize image
                img = Image.open(img_path)
                img.thumbnail((thumb_size, thumb_size), Image.Resampling.LANCZOS)
                photo = ImageTk.PhotoImage(img)
                gallery_image_refs.append(photo)

                # Create frame for each thumbnail
                thumb_frame = tk.Frame(scrollable_frame, bg="#e0e0e0", padx=5, pady=5)
                thumb_frame.grid(row=row, column=col, padx=5, pady=5, sticky="n")

                # Image label
                img_label = tk.Label(thumb_frame, image=photo, bg="white", relief="solid", bd=1)
                img_label.pack()

                # Filename label (shortened)
                filename = os.path.basename(img_path)
                if len(filename) > 25:
                    display_name = filename[:22] + "..."
                else:
                    display_name = filename

                name_label = tk.Label(
                    thumb_frame,
                    text=display_name,
                    font=("Helvetica", 8),
                    bg="#e0e0e0",
                    wraplength=thumb_size
                )
                name_label.pack()

                # Bind click to show full image
                def show_full_image(path=img_path):
                    show_zoomed_die_image(path)

                img_label.bind("<Button-1>", lambda e, p=img_path: show_zoomed_die_image(p))
                img_label.bind("<Enter>", lambda e, lbl=img_label: lbl.config(relief="raised", bd=2))
                img_label.bind("<Leave>", lambda e, lbl=img_label: lbl.config(relief="solid", bd=1))

                # Move to next position
                col += 1
                if col >= num_cols:
                    col = 0
                    row += 1

            except Exception as e:
                print(f"Error loading thumbnail for {img_path}: {e}")
                continue

        # Update scroll region
        scrollable_frame.update_idletasks()
        gallery_canvas.configure(scrollregion=gallery_canvas.bbox("all"))

    # Bind refresh on settings change
    thumb_size_combo.bind("<<ComboboxSelected>>", lambda e: load_thumbnails())
    cols_combo.bind("<<ComboboxSelected>>", lambda e: load_thumbnails())
    filter_entry.bind("<Return>", lambda e: load_thumbnails())
    filter_entry.bind("<KeyRelease>", lambda e: gallery_win.after(500, load_thumbnails))

    # Refresh button
    refresh_btn = tk.Button(
        control_frame,
        text="Refresh",
        command=load_thumbnails,
        font=("Helvetica", 10)
    )
    refresh_btn.pack(side=tk.LEFT, padx=10)

    # Load initial thumbnails after window is displayed
    gallery_win.after(100, load_thumbnails)

    # Cleanup on close
    def on_gallery_close():
        gallery_canvas.unbind_all("<MouseWheel>")
        gallery_image_refs.clear()
        gallery_win.destroy()

    gallery_win.protocol("WM_DELETE_WINDOW", on_gallery_close)


def find_die_images(x_coord, y_coord, image_type_filter=None):
    """Find images matching the given die coordinates and optional type filter"""
    global die_image_directory, available_image_types

    if not die_image_directory:
        return []

    matching_images = []
    found_types = set(["All"])  # Always include "All" option

    try:
        import re

        # List all files in the directory
        for filename in os.listdir(die_image_directory):
            # Check for image file extensions
            if not filename.lower().endswith(('.jpg', '.jpeg', '.png', '.gif', '.bmp', '.tif', '.tiff')):
                continue

            # Look for coordinate patterns in filename
            # Patterns: X19_Y46, X19-Y46, _X19_Y46_, Die_X19_Y46
            # Pattern 1: X##_Y## or X##-Y##
            pattern1 = rf'[_\-]X{x_coord}[_\-]Y{y_coord}[_\-\.]'
            # Pattern 2: _X##_Y##_ (with underscores)
            pattern2 = rf'_X{x_coord}_Y{y_coord}_'
            # Pattern 3: -X##-Y##- (with dashes)
            pattern3 = rf'-X{x_coord}-Y{y_coord}-'

            if (re.search(pattern1, filename, re.IGNORECASE) or
                re.search(pattern2, filename, re.IGNORECASE) or
                re.search(pattern3, filename, re.IGNORECASE)):

                # Extract image type from filename
                # Pattern: VPG-XHAIR-12FRAME or VPG-ALLON-12FRAME
                type_match = re.search(r'VPG-([A-Z0-9]+)-', filename, re.IGNORECASE)
                if type_match:
                    img_type = type_match.group(1).upper()
                    found_types.add(img_type)

                    # Apply filter if specified
                    if image_type_filter and image_type_filter != "All":
                        if img_type != image_type_filter.upper():
                            continue

                full_path = os.path.join(die_image_directory, filename)
                matching_images.append(full_path)
                print(f"Found matching image: {filename}")

        # Update available types in combobox
        available_image_types = sorted(list(found_types))
        if "All" in available_image_types:
            available_image_types.remove("All")
            available_image_types.insert(0, "All")

        # Update combobox values
        current_selection = image_type_var.get()
        image_type_combobox["values"] = available_image_types
        if current_selection not in available_image_types:
            image_type_var.set("All")

    except Exception as e:
        print(f"Error searching for die images: {e}")

    return matching_images


def refresh_die_images():
    """Refresh die images based on current filter selection"""
    global current_selected_die

    if current_selected_die is not None:
        x_coord, y_coord = current_selected_die
        display_die_images(x_coord, y_coord)



# Note: die_image_panel, plm panels, and related widgets are defined earlier
# (around line 1926) before heatmap_display_frame to ensure proper pack order

# Add bindings for refresh functions
image_type_combobox.bind("<<ComboboxSelected>>", lambda e: refresh_die_images())
plm_type_combobox.bind("<<ComboboxSelected>>", lambda e: refresh_plm_files())


def find_plm_files(x_coord, y_coord, plm_type_filter=None):
    """Find PLM files matching the given die coordinates and optional type filter"""
    global available_plm_types, plm_file_directory

    # First try the global plm_file_directory (auto-detected), then fall back to config_dirs
    plm_dir = plm_file_directory
    if not plm_dir or not os.path.exists(plm_dir):
        plm_dir = config_dirs["plm"].get() if "plm" in config_dirs else None
    print(f"  find_plm_files: plm_dir = {plm_dir}")

    if not plm_dir or not os.path.exists(plm_dir):
        print(f"  find_plm_files: PLM dir not set or doesn't exist")
        return []

    matching_files = []
    found_types = set(["All"])

    try:
        import re

        files_in_dir = os.listdir(plm_dir)
        print(f"  find_plm_files: {len(files_in_dir)} files in PLM directory")

        for filename in files_in_dir:
            # Check for PLM file extensions (common ones)
            if not filename.lower().endswith(('.plm', '.txt', '.csv', '.dat', '.xml', '.json')):
                continue

            # Look for coordinate patterns in filename
            # Pattern for Die_X##_Y## format (e.g., Die_X31_Y28)
            pattern1 = rf'Die_X{x_coord}_Y{y_coord}[_\.]'
            # Pattern for W##-X##-Y## format (e.g., W21-X31-Y28)
            pattern2 = rf'-X{x_coord}-Y{y_coord}[_\-]'
            # Pattern for generic underscore/dash separated coordinates
            pattern3 = rf'[_\-]X{x_coord}[_\-]Y{y_coord}[_\-\.]'

            match1 = re.search(pattern1, filename, re.IGNORECASE)
            match2 = re.search(pattern2, filename, re.IGNORECASE)
            match3 = re.search(pattern3, filename, re.IGNORECASE)

            if match1 or match2 or match3:

                # Extract PLM type from filename if present
                type_match = re.search(r'PLM-([A-Z0-9]+)-', filename, re.IGNORECASE)
                if type_match:
                    plm_type = type_match.group(1).upper()
                    found_types.add(plm_type)

                    if plm_type_filter and plm_type_filter != "All":
                        if plm_type != plm_type_filter.upper():
                            continue
                else:
                    # Try to extract type from file extension or other patterns
                    ext = os.path.splitext(filename)[1].upper().replace('.', '')
                    found_types.add(ext)

                    if plm_type_filter and plm_type_filter != "All":
                        if ext != plm_type_filter.upper():
                            continue

                full_path = os.path.join(plm_dir, filename)
                matching_files.append(full_path)
                print(f"Found matching PLM file: {filename}")

        # Update available types
        available_plm_types = sorted(list(found_types))
        if "All" in available_plm_types:
            available_plm_types.remove("All")
            available_plm_types.insert(0, "All")

        current_selection = plm_type_var.get()
        plm_type_combobox["values"] = available_plm_types
        if current_selection not in available_plm_types:
            plm_type_var.set("All")

    except Exception as e:
        print(f"Error searching for PLM files: {e}")

    return matching_files

def show_multi_wafer_plm_window(x_coord, y_coord):
    """Show a window with PLM files from ALL wafers with 4 tabs: Heatmap, Distribution, Profile, Boxplot"""
    global multi_wafer_wafer_configs, multi_wafer_wafer_ids

    print(f"show_multi_wafer_plm_window called for die ({x_coord}, {y_coord})")

    # Collect ALL PLM files from all wafers (to get available types)
    all_plm_types = set()
    # Use a dict with a list inside to ensure the reference is maintained
    all_wafer_plm_unfiltered_data = {'wafers': []}  # [(wafer_id, plm_files, plm_dir), ...]

    for wafer_id, config in zip(multi_wafer_wafer_ids, multi_wafer_wafer_configs):
        plm_dir = config.get('plm_dir')
        if plm_dir:
            files = find_plm_files_in_dir(x_coord, y_coord, plm_dir, None)
            if files:
                all_wafer_plm_unfiltered_data['wafers'].append((wafer_id, files, plm_dir))
                import re
                for f in files:
                    fname = os.path.basename(f)
                    type_match = re.search(r'Die_X\d+_Y\d+_([A-Za-z0-9\-]+)_', fname)
                    if type_match:
                        all_plm_types.add(type_match.group(1))

    if not all_wafer_plm_unfiltered_data['wafers']:
        messagebox.showinfo("No PLM Files", f"No PLM files found for die ({x_coord}, {y_coord})")
        return

    # Create window maximized
    zoom_win = tk.Toplevel(main_win)
    zoom_win.title(f"PLM Comparison - Die X={x_coord}, Y={y_coord} - {len(all_wafer_plm_unfiltered_data['wafers'])} Wafer(s)")
    zoom_win.geometry("1600x950")
    zoom_win.state('zoomed')

    all_figures = []

    # Store loaded PLM data for all wafers: [(wafer_id, wafer_idx, plm_path, plm_data), ...]
    all_plm_data = []

    # History of selected positions
    position_history = []
    current_position = {'x': x_coord, 'y': y_coord}

    # Top frame for PLM type selection
    top_frame = tk.Frame(zoom_win, bg="#e0e0e0", height=50)
    top_frame.pack(fill=tk.X, padx=5, pady=5)
    top_frame.pack_propagate(False)

    tk.Label(
        top_frame,
        text=f"📊 PLM Comparison - Die ({x_coord}, {y_coord})",
        font=("Helvetica", 14, "bold"),
        bg="#e0e0e0"
    ).pack(side=tk.LEFT, padx=15, pady=10)

    tk.Label(
        top_frame,
        text="PLM Type:",
        font=("Helvetica", 11),
        bg="#e0e0e0"
    ).pack(side=tk.LEFT, padx=(30, 5))

    plm_type_options = ["All"] + sorted(list(all_plm_types))
    plm_type_var = tk.StringVar(value=plm_type_options[1] if len(plm_type_options) > 1 else "All")
    plm_type_combo = ttk.Combobox(
        top_frame,
        textvariable=plm_type_var,
        values=plm_type_options,
        state="readonly",
        width=30,
        font=("Helvetica", 10)
    )
    plm_type_combo.pack(side=tk.LEFT, padx=5, pady=10)

    # Main content frame with history on left and tabs on right
    main_content_frame = tk.Frame(zoom_win, bg="#f0f0f0")
    main_content_frame.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)

    # ===== LEFT SIDE: History Panel =====
    history_frame = tk.Frame(main_content_frame, bg="#e8e8e8", width=200, relief=tk.RIDGE, bd=1)
    history_frame.pack(side=tk.LEFT, fill=tk.Y, padx=(0, 5))
    history_frame.pack_propagate(False)

    tk.Label(
        history_frame,
        text="📜 History",
        font=("Helvetica", 12, "bold"),
        bg="#e8e8e8"
    ).pack(pady=10)

    history_listbox = tk.Listbox(
        history_frame,
        font=("Helvetica", 10),
        bg="white",
        selectbackground="#1976D2",
        selectforeground="white",
        height=30
    )
    history_listbox.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)

    def add_to_history(x, y):
        """Add position to history"""
        pos_str = f"Die ({x}, {y})"
        if pos_str not in position_history:
            position_history.append(pos_str)
            history_listbox.insert(tk.END, pos_str)

    def on_history_select(event):
        """Load position from history"""
        selection = history_listbox.curselection()
        if selection:
            pos_str = history_listbox.get(selection[0])
            # Parse coordinates from string "Die (x, y)"
            import re
            match = re.match(r'Die \((\d+), (\d+)\)', pos_str)
            if match:
                new_x, new_y = int(match.group(1)), int(match.group(2))
                current_position['x'] = new_x
                current_position['y'] = new_y

                # Update title with selected position
                zoom_win.title(f"PLM Comparison - Die X={new_x}, Y={new_y}")

                # Reload PLM data for the new position from all wafers
                print(f"History select: Reloading PLM data for position ({new_x}, {new_y})")
                all_plm_types.clear()
                all_wafer_plm_unfiltered_data['wafers'].clear()

                for wafer_id, config in zip(multi_wafer_wafer_ids, multi_wafer_wafer_configs):
                    plm_dir = config.get('plm_dir')
                    if plm_dir:
                        # Find PLM files for the NEW position
                        files = find_plm_files_in_dir(new_x, new_y, plm_dir, None)
                        print(f"  Wafer {wafer_id}: found {len(files)} files")
                        if files:
                            all_wafer_plm_unfiltered_data['wafers'].append((wafer_id, files, plm_dir))
                            for f in files:
                                fname = os.path.basename(f)
                                type_match = re.search(r'Die_X\d+_Y\d+_([A-Za-z0-9\-]+)_', fname)
                                if type_match:
                                    all_plm_types.add(type_match.group(1))

                # Update PLM type combo with new types
                plm_type_options = ["All"] + sorted(list(all_plm_types))
                plm_type_combo['values'] = plm_type_options
                if len(plm_type_options) > 1:
                    plm_type_var.set(plm_type_options[1])
                else:
                    plm_type_var.set("All")

                print(f"History select: Changed to position ({new_x}, {new_y}), found {len(all_wafer_plm_unfiltered_data['wafers'])} wafers with data")

                # Update all tabs with new data
                update_all_tabs()

                # Keep selection visible in blue
                history_listbox.activate(selection[0])
                history_listbox.see(selection[0])
                # Give focus back to listbox so selection stays blue
                history_listbox.focus_set()

    history_listbox.bind('<<ListboxSelect>>', on_history_select)

    # Add initial position to history
    add_to_history(x_coord, y_coord)

    # If Select Positions mode is active, add all pre-selected positions to history
    if multi_wafer_select_positions_var.get() and multi_wafer_selected_positions:
        for pos_x, pos_y in multi_wafer_selected_positions:
            if (pos_x, pos_y) != (x_coord, y_coord):  # Don't add the current position twice
                add_to_history(pos_x, pos_y)

    # ===== RIGHT SIDE: Tab Notebook =====
    tab_notebook = ttk.Notebook(main_content_frame)
    tab_notebook.pack(side=tk.RIGHT, fill=tk.BOTH, expand=True)

    # Create 5 tabs (added Diffmap)
    tab_heatmap = tk.Frame(tab_notebook, bg="#f0f0f0")
    tab_diffmap = tk.Frame(tab_notebook, bg="#f0f0f0")
    tab_distribution = tk.Frame(tab_notebook, bg="#f0f0f0")
    tab_profile = tk.Frame(tab_notebook, bg="#f0f0f0")
    tab_boxplot = tk.Frame(tab_notebook, bg="#f0f0f0")

    tab_notebook.add(tab_heatmap, text="🔥 Heatmap")
    tab_notebook.add(tab_diffmap, text="🔀 Diffmap")
    tab_notebook.add(tab_distribution, text="📊 Distribution")
    tab_notebook.add(tab_profile, text="📈 Profile")
    tab_notebook.add(tab_boxplot, text="📦 Boxplot")

    # ===== TAB 1: HEATMAP - Professional layout with dynamic sizing =====
    def create_heatmap_tab():
        nonlocal all_figures

        # Clear existing content
        for widget in tab_heatmap.winfo_children():
            widget.destroy()

        # Get filtered PLM data using already loaded files
        selected_type = plm_type_var.get()
        filtered_plm_data = []

        for wafer_idx, (wafer_id, files, plm_dir) in enumerate(all_wafer_plm_unfiltered_data['wafers']):
            # Use the already loaded files directly, not find_plm_files_in_dir
            if selected_type == "All":
                target_files = files
            else:
                import re
                target_files = [f for f in files if re.search(rf'Die_X\d+_Y\d+_{re.escape(selected_type)}_', os.path.basename(f))]

            for plm_path in target_files:
                try:
                    plm_data = load_plm_as_matrix(plm_path)
                    if plm_data is not None and plm_data.size > 0:
                        filtered_plm_data.append((wafer_id, wafer_idx, plm_path, plm_data))
                except Exception as e:
                    print(f"Error loading PLM {plm_path}: {e}")

        if not filtered_plm_data:
            tk.Label(tab_heatmap, text="No PLM data available", font=("Helvetica", 14), bg="#f0f0f0").pack(expand=True)
            return

        num_plms = len(filtered_plm_data)

        # Calculate global min/max for shared colorbar
        global_min = min(np.nanmin(data[3]) for data in filtered_plm_data)
        global_max = max(np.nanmax(data[3]) for data in filtered_plm_data)

        # Track selected axis for zoom
        selected_ax_ref = [None]
        all_ax_borders = {}

        # Main container - no scrolling for first 4, scroll only if more
        if num_plms <= 4:
            # Direct frame, no scrolling needed
            container = tk.Frame(tab_heatmap, bg="white")
            container.pack(fill=tk.BOTH, expand=True)
        else:
            # Scrollable for more than 4
            canvas = tk.Canvas(tab_heatmap, highlightthickness=0, bg="white")
            scrollbar = ttk.Scrollbar(tab_heatmap, orient="vertical", command=canvas.yview)
            container = tk.Frame(canvas, bg="white")

            container.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
            canvas.create_window((0, 0), window=container, anchor="nw")
            canvas.configure(yscrollcommand=scrollbar.set)

            scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
            canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        # Process in groups of 4
        for page_idx in range(0, num_plms, 4):
            page_data = filtered_plm_data[page_idx:page_idx + 4]
            num_in_page = len(page_data)

            # Create figure - use tight_layout instead of constrained_layout
            if num_in_page == 1:
                fig, axes_arr = plt.subplots(1, 1, figsize=(9, 7))
                axes = [axes_arr]
            elif num_in_page == 2:
                fig, axes_arr = plt.subplots(1, 2, figsize=(12, 5))
                axes = list(axes_arr)
            elif num_in_page == 3:
                fig, axes_arr = plt.subplots(2, 2, figsize=(12, 9))
                axes = [axes_arr[0, 0], axes_arr[0, 1], axes_arr[1, 0]]
                axes_arr[1, 1].set_visible(False)
            else:  # 4
                fig, axes_arr = plt.subplots(2, 2, figsize=(12, 9))
                axes = [axes_arr[0, 0], axes_arr[0, 1], axes_arr[1, 0], axes_arr[1, 1]]

            fig.patch.set_facecolor('white')
            im_last = None

            for idx, (wafer_id, wafer_idx, plm_path, plm_data) in enumerate(page_data):
                ax = axes[idx]

                im = ax.imshow(plm_data, cmap='viridis', aspect='auto', vmin=global_min, vmax=global_max)
                im_last = im

                # Title - kurz und prägnant
                short_id = str(wafer_id).split('_')[-3] if '_' in str(wafer_id) else str(wafer_id)[:15]
                ax.set_title(f"W{wafer_idx + 1}: {short_id}", fontsize=10, fontweight='bold')

                ax.set_xlabel("Column", fontsize=9)
                ax.set_ylabel("Row", fontsize=9)
                ax.tick_params(axis='both', labelsize=8)

                # Stats box
                stats_text = f"Min:{np.nanmin(plm_data):.3f}\nMax:{np.nanmax(plm_data):.3f}\nMean:{np.nanmean(plm_data):.3f}"
                ax.text(0.02, 0.98, stats_text, transform=ax.transAxes, fontsize=7,
                       va='top', ha='left', family='monospace',
                       bbox=dict(boxstyle='round,pad=0.2', facecolor='white', edgecolor='gray', alpha=0.9))

                # Border for selection
                for spine in ax.spines.values():
                    spine.set_linewidth(2)
                    spine.set_color('#cccccc')
                all_ax_borders[ax] = ax.spines

            # Colorbar - rechts von allen subplots
            fig.subplots_adjust(right=0.88)
            cbar_ax = fig.add_axes([0.90, 0.15, 0.02, 0.7])
            cbar = fig.colorbar(im_last, cax=cbar_ax)
            cbar.ax.tick_params(labelsize=8)

            # Page title if multiple pages
            if num_plms > 4:
                page_num = page_idx // 4 + 1
                total_pages = (num_plms + 3) // 4
                fig.suptitle(f"Page {page_num}/{total_pages}", fontsize=10, y=0.98)

            fig.tight_layout(rect=[0, 0, 0.88, 0.96])

            # Embed in tkinter
            canvas_mpl = FigureCanvasTkAgg(fig, master=container)
            widget = canvas_mpl.get_tk_widget()
            widget.pack(fill=tk.BOTH, expand=True, padx=0, pady=0)
            canvas_mpl.draw()
            all_figures.append(fig)

            # Toolbar
            toolbar_frame = tk.Frame(container, bg="#f5f5f5", height=35)
            toolbar_frame.pack(fill=tk.X, padx=0, pady=(0, 5))
            toolbar_frame.pack_propagate(False)
            toolbar = NavigationToolbar2Tk(canvas_mpl, toolbar_frame)
            toolbar.update()

            # Click to select (blue border)
            def make_click_handler(ax_list, borders_dict, mpl_canvas, sel_ref):
                def handler(event):
                    if event.inaxes in ax_list:
                        for a, spines in borders_dict.items():
                            for s in spines.values():
                                s.set_linewidth(2)
                                s.set_color('#cccccc')
                        sel_ref[0] = event.inaxes
                        for s in borders_dict[event.inaxes].values():
                            s.set_linewidth(3)
                            s.set_color('#1565C0')
                        mpl_canvas.draw()
                return handler

            # Scroll to zoom (only selected)
            def make_zoom_handler(ax_list, mpl_canvas, sel_ref):
                def handler(event):
                    if sel_ref[0] is None or event.inaxes != sel_ref[0]:
                        return
                    ax = sel_ref[0]
                    xdata, ydata = event.xdata, event.ydata
                    if xdata is None or ydata is None:
                        return
                    base_scale = 1.3
                    scale = 1/base_scale if event.button == 'up' else base_scale
                    xlim, ylim = ax.get_xlim(), ax.get_ylim()
                    xrange = (xlim[1] - xlim[0]) * scale
                    yrange = (ylim[1] - ylim[0]) * scale
                    ax.set_xlim([xdata - xrange * (xdata - xlim[0]) / (xlim[1] - xlim[0]),
                                 xdata + xrange * (xlim[1] - xdata) / (xlim[1] - xlim[0])])
                    ax.set_ylim([ydata - yrange * (ydata - ylim[0]) / (ylim[1] - ylim[0]),
                                 ydata + yrange * (ylim[1] - ydata) / (ylim[1] - ylim[0])])
                    mpl_canvas.draw()
                return handler

            fig.canvas.mpl_connect('button_press_event', make_click_handler(axes, all_ax_borders, canvas_mpl, selected_ax_ref))
            fig.canvas.mpl_connect('scroll_event', make_zoom_handler(axes, canvas_mpl, selected_ax_ref))

    # ===== TAB 2: DIFFMAP (PLM1 - PLM2) =====
    def create_diffmap_tab():
        nonlocal all_figures

        # Clear existing content
        for widget in tab_diffmap.winfo_children():
            widget.destroy()

        # Control frame to show selected parameters
        control_frame = tk.Frame(tab_diffmap, bg="#e0e0e0")
        control_frame.pack(fill=tk.X, padx=10, pady=5)

        tk.Label(control_frame, text="PLM Type:", font=("Helvetica", 10), bg="#e0e0e0").pack(side=tk.LEFT, padx=5)
        tk.Label(control_frame, text=plm_type_var.get(), font=("Helvetica", 10, "bold"), bg="#e0e0e0", fg="#1976D2").pack(side=tk.LEFT, padx=5)

        # Get filtered PLM data using already loaded files
        selected_type = plm_type_var.get()
        filtered_plm_data = []

        for wafer_idx, (wafer_id, files, plm_dir) in enumerate(all_wafer_plm_unfiltered_data['wafers']):
            # Use the already loaded files directly
            if selected_type == "All":
                target_files = files
            else:
                import re
                target_files = [f for f in files if re.search(rf'Die_X\d+_Y\d+_{re.escape(selected_type)}_', os.path.basename(f))]

            for plm_path in target_files:
                try:
                    plm_data = load_plm_as_matrix(plm_path)
                    if plm_data is not None and plm_data.size > 0:
                        filtered_plm_data.append((wafer_id, wafer_idx, plm_path, plm_data))
                except Exception as e:
                    print(f"Error loading PLM {plm_path}: {e}")

        if len(filtered_plm_data) < 2:
            tk.Label(tab_diffmap, text="Need at least 2 PLM files for Diffmap (PLM1 - PLM2)", font=("Helvetica", 12), bg="#f0f0f0").pack(expand=True)
            return

        # Get first two PLMs for difference
        wafer_id_1, wafer_idx_1, plm_path_1, plm_data_1 = filtered_plm_data[0]
        wafer_id_2, wafer_idx_2, plm_path_2, plm_data_2 = filtered_plm_data[1]

        # Make sure they have the same shape by padding if needed
        shape_1 = plm_data_1.shape
        shape_2 = plm_data_2.shape
        max_shape = (max(shape_1[0], shape_2[0]), max(shape_1[1], shape_2[1]))

        plm_data_1_padded = np.full(max_shape, np.nan)
        plm_data_1_padded[:shape_1[0], :shape_1[1]] = plm_data_1

        plm_data_2_padded = np.full(max_shape, np.nan)
        plm_data_2_padded[:shape_2[0], :shape_2[1]] = plm_data_2

        # Calculate difference
        diff_data = plm_data_2_padded - plm_data_1_padded

        # Create figure for diffmap
        fig, ax = plt.subplots(figsize=(10, 8))
        fig.patch.set_facecolor('white')

        # Use diverging colormap for difference
        diff_min = np.nanmin(diff_data)
        diff_max = np.nanmax(diff_data)
        diff_abs_max = max(abs(diff_min), abs(diff_max))

        im = ax.imshow(diff_data, cmap='RdBu_r', aspect='auto', vmin=-diff_abs_max, vmax=diff_abs_max)

        # Title
        short_id_1 = str(wafer_id_1).split('_')[-3] if '_' in str(wafer_id_1) else str(wafer_id_1)[:15]
        short_id_2 = str(wafer_id_2).split('_')[-3] if '_' in str(wafer_id_2) else str(wafer_id_2)[:15]
        ax.set_title(f"Diffmap: W{wafer_idx_2 + 1} - W{wafer_idx_1 + 1}\n({short_id_2} - {short_id_1})", fontsize=12, fontweight='bold')

        ax.set_xlabel("Column", fontsize=10)
        ax.set_ylabel("Row", fontsize=10)
        ax.tick_params(axis='both', labelsize=8)

        # Stats box
        diff_valid = diff_data[~np.isnan(diff_data)]
        if len(diff_valid) > 0:
            stats_text = f"Min:{np.nanmin(diff_data):.3f}\nMax:{np.nanmax(diff_data):.3f}\nMean:{np.nanmean(diff_data):.3f}"
        else:
            stats_text = "No valid data"
        ax.text(0.02, 0.98, stats_text, transform=ax.transAxes, fontsize=8,
               va='top', ha='left', family='monospace',
               bbox=dict(boxstyle='round,pad=0.2', facecolor='white', edgecolor='gray', alpha=0.9))

        # Colorbar
        fig.subplots_adjust(right=0.88)
        cbar_ax = fig.add_axes([0.90, 0.15, 0.02, 0.7])
        cbar = fig.colorbar(im, cax=cbar_ax)
        cbar.ax.tick_params(labelsize=8)
        cbar.set_label('Difference', fontsize=9)

        fig.tight_layout(rect=[0, 0, 0.88, 1])

        # Embed in tkinter
        container = tk.Frame(tab_diffmap, bg="white")
        container.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)

        canvas_mpl = FigureCanvasTkAgg(fig, master=container)
        widget = canvas_mpl.get_tk_widget()
        widget.pack(fill=tk.BOTH, expand=True)
        canvas_mpl.draw()
        all_figures.append(fig)

        # Toolbar
        toolbar_frame = tk.Frame(container, bg="#f5f5f5", height=35)
        toolbar_frame.pack(fill=tk.X, padx=0, pady=(0, 5))
        toolbar_frame.pack_propagate(False)
        toolbar = NavigationToolbar2Tk(canvas_mpl, toolbar_frame)
        toolbar.update()

    # ===== TAB 3: DISTRIBUTION =====
    def create_distribution_tab():
        nonlocal all_figures

        # Clear existing content
        for widget in tab_distribution.winfo_children():
            widget.destroy()

        # Get filtered PLM data using already loaded files
        selected_type = plm_type_var.get()
        filtered_plm_data = []

        for wafer_idx, (wafer_id, files, plm_dir) in enumerate(all_wafer_plm_unfiltered_data['wafers']):
            # Use the already loaded files directly
            if selected_type == "All":
                target_files = files
            else:
                import re
                target_files = [f for f in files if re.search(rf'Die_X\d+_Y\d+_{re.escape(selected_type)}_', os.path.basename(f))]

            for plm_path in target_files:
                try:
                    plm_data = load_plm_as_matrix(plm_path)
                    if plm_data is not None and plm_data.size > 0:
                        filtered_plm_data.append((wafer_id, wafer_idx, plm_path, plm_data))
                except:
                    pass

        if not filtered_plm_data:
            tk.Label(tab_distribution, text="No PLM data available", font=("Helvetica", 12), bg="#f0f0f0").pack(pady=50)
            return

        # Controls frame
        control_frame = tk.Frame(tab_distribution, bg="#e0e0e0")
        control_frame.pack(fill=tk.X, padx=10, pady=5)

        tk.Label(control_frame, text="Distribution Type:", font=("Helvetica", 10), bg="#e0e0e0").pack(side=tk.LEFT, padx=5)
        dist_type_var = tk.StringVar(value="CDF")
        dist_combo = ttk.Combobox(control_frame, textvariable=dist_type_var, values=["CDF", "PDF"], state="readonly", width=10)
        dist_combo.pack(side=tk.LEFT, padx=5)

        tk.Label(control_frame, text="Use Diffmap:", font=("Helvetica", 10), bg="#e0e0e0").pack(side=tk.LEFT, padx=(20, 5))
        use_diffmap_var = tk.BooleanVar(value=False)
        diffmap_check = ttk.Checkbutton(control_frame, variable=use_diffmap_var)
        diffmap_check.pack(side=tk.LEFT, padx=5)

        # Plot frame
        plot_frame = tk.Frame(tab_distribution, bg="#f0f0f0")
        plot_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)

        dist_fig_ref = [None]

        def update_distribution():
            for w in plot_frame.winfo_children():
                w.destroy()
            if dist_fig_ref[0]:
                plt.close(dist_fig_ref[0])

            # Create combined distribution plot
            fig_dist, ax_dist = plt.subplots(figsize=(12, 8))
            fig_dist.patch.set_facecolor('#f5f5f5')
            dist_fig_ref[0] = fig_dist

            colors = plt.cm.tab10.colors

            # Prepare data: either original or diffmap
            data_to_plot = filtered_plm_data
            if use_diffmap_var.get() and len(filtered_plm_data) >= 2:
                # Calculate diffmap data (PLM2 - PLM1)
                wafer_id_1, wafer_idx_1, plm_path_1, plm_data_1 = filtered_plm_data[0]
                wafer_id_2, wafer_idx_2, plm_path_2, plm_data_2 = filtered_plm_data[1]

                # Pad to same shape
                shape_1 = plm_data_1.shape
                shape_2 = plm_data_2.shape
                max_shape = (max(shape_1[0], shape_2[0]), max(shape_1[1], shape_2[1]))

                plm_data_1_padded = np.full(max_shape, np.nan)
                plm_data_1_padded[:shape_1[0], :shape_1[1]] = plm_data_1

                plm_data_2_padded = np.full(max_shape, np.nan)
                plm_data_2_padded[:shape_2[0], :shape_2[1]] = plm_data_2

                diff_data = plm_data_2_padded - plm_data_1_padded
                data_to_plot = [(wafer_id_2, wafer_idx_2, plm_path_2, diff_data)]

            for idx, (wafer_id, wafer_idx, plm_path, plm_data) in enumerate(data_to_plot):
                valid_data = plm_data[~np.isnan(plm_data)].flatten()
                if len(valid_data) == 0:
                    continue

                color = colors[idx % len(colors)]
                short_id = str(wafer_id)[:25]

                label_suffix = " (Diffmap)" if use_diffmap_var.get() and len(filtered_plm_data) >= 2 else ""

                if dist_type_var.get() == "CDF":
                    sorted_d = np.sort(valid_data)
                    cumulative = np.arange(1, len(sorted_d) + 1) / len(sorted_d)
                    ax_dist.plot(sorted_d, cumulative, color=color, linewidth=2, label=f"Wafer {wafer_idx + 1}: {short_id}{label_suffix}")
                else:
                    ax_dist.hist(valid_data, bins=50, density=True, alpha=0.5, color=color,
                                label=f"Wafer {wafer_idx + 1}: {short_id}{label_suffix}", edgecolor='white')

                    # Add sigma lines for PDF
                    mean_val = np.mean(valid_data)
                    std_val = np.std(valid_data)

                    # Get y-axis max for line heights
                    y_max = ax_dist.get_ylim()[1]

                    # Mean line
                    ax_dist.axvline(mean_val, color=color, linestyle='-', linewidth=2, alpha=0.8, label=f"μ")

                    # Sigma lines
                    ax_dist.axvline(mean_val - std_val, color=color, linestyle='--', linewidth=1.5, alpha=0.6)
                    ax_dist.axvline(mean_val + std_val, color=color, linestyle='--', linewidth=1.5, alpha=0.6, label=f"±1σ")

                    # 2-Sigma lines
                    ax_dist.axvline(mean_val - 2*std_val, color=color, linestyle=':', linewidth=1, alpha=0.5)
                    ax_dist.axvline(mean_val + 2*std_val, color=color, linestyle=':', linewidth=1, alpha=0.5, label=f"±2σ")

                    # 3-Sigma lines
                    ax_dist.axvline(mean_val - 3*std_val, color=color, linestyle='-.', linewidth=1, alpha=0.4)
                    ax_dist.axvline(mean_val + 3*std_val, color=color, linestyle='-.', linewidth=1, alpha=0.4, label=f"±3σ")

            ax_dist.set_xlabel("Value", fontsize=12)
            ax_dist.set_ylabel("Cumulative Probability" if dist_type_var.get() == "CDF" else "Density", fontsize=12)
            plot_title = f"{dist_type_var.get()} - All Wafers (Diffmap)" if use_diffmap_var.get() and len(filtered_plm_data) >= 2 else f"{dist_type_var.get()} - All Wafers"
            ax_dist.set_title(plot_title, fontsize=14, fontweight="bold")
            ax_dist.legend(loc='best', fontsize=9)
            ax_dist.grid(True, alpha=0.3)
            fig_dist.tight_layout()

            canvas_dist = FigureCanvasTkAgg(fig_dist, master=plot_frame)
            canvas_dist.get_tk_widget().pack(fill=tk.BOTH, expand=True)
            canvas_dist.draw()
            all_figures.append(fig_dist)

            # Add toolbar
            toolbar_frame = tk.Frame(plot_frame)
            toolbar_frame.pack(fill=tk.X)
            toolbar = NavigationToolbar2Tk(canvas_dist, toolbar_frame)
            toolbar.update()

        dist_combo.bind("<<ComboboxSelected>>", lambda e: update_distribution())
        diffmap_check.configure(command=update_distribution)
        update_distribution()

