def update_plm_position_history():
    """Update the position history combobox with selected positions"""
    global multi_wafer_selected_positions
    positions = [f"X={x}, Y={y}" for x, y in multi_wafer_selected_positions]
    multi_wafer_plm_position_combo['values'] = positions
    if positions:
        multi_wafer_plm_position_combo.set(positions[-1])  # Select most recent
    else:
        multi_wafer_plm_position_combo.set("")

def on_plm_position_selected(event=None):
    """Handle position selection from history combobox"""
    selected = multi_wafer_plm_position_var.get()
    if selected:
        # Parse X=value, Y=value format
        import re
        match = re.match(r'X=(-?\d+),\s*Y=(-?\d+)', selected)
        if match:
            x_coord = int(match.group(1))
            y_coord = int(match.group(2))
            display_multi_wafer_plm_files(x_coord, y_coord)

def clear_plm_position_history():
    """Clear the position history"""
    global multi_wafer_selected_positions
    multi_wafer_selected_positions.clear()
    update_plm_position_history()
    multi_wafer_plm_die_label.config(text="Click on a die", fg="gray")
    # Clear PLM display
    for widget in multi_wafer_plm_scrollable_frame.winfo_children():
        widget.destroy()

