def find_plm_files_in_dir(x_coord, y_coord, plm_dir, plm_type_filter=None):
    """Find PLM files matching coordinates in a specific directory - reuses logic from find_plm_files"""
    if not plm_dir or not os.path.exists(plm_dir):
        return []

    matching_files = []

    try:
        import re
        for filename in os.listdir(plm_dir):
            if not filename.lower().endswith(('.plm', '.txt', '.csv', '.dat', '.xml', '.json')):
                continue

            # Same patterns as find_plm_files
            pattern1 = rf'Die_X{x_coord}_Y{y_coord}[_\.]'
            pattern2 = rf'-X{x_coord}-Y{y_coord}[_\-]'
            pattern3 = rf'[_\-]X{x_coord}[_\-]Y{y_coord}[_\-\.]'

            if re.search(pattern1, filename, re.IGNORECASE) or \
               re.search(pattern2, filename, re.IGNORECASE) or \
               re.search(pattern3, filename, re.IGNORECASE):

                # Extract PLM type
                type_match = re.search(r'PLM-([A-Z0-9]+)-', filename, re.IGNORECASE)
                if type_match:
                    plm_type = type_match.group(1).upper()
                    if plm_type_filter and plm_type_filter != "All":
                        if plm_type != plm_type_filter.upper():
                            continue

                full_path = os.path.join(plm_dir, filename)
                matching_files.append(full_path)
    except Exception as e:
        print(f"Error finding PLM files in {plm_dir}: {e}")

    return matching_files

def display_multi_wafer_plm_files(x_coord, y_coord):
    """Display PLM files for selected die from ALL loaded wafers side by side"""
    global multi_wafer_plm_refs, multi_wafer_selected_die_plm
    global multi_wafer_wafer_configs, multi_wafer_wafer_ids

    print(f"display_multi_wafer_plm_files called for die ({x_coord}, {y_coord})")

    multi_wafer_selected_die_plm = (x_coord, y_coord)

    # Update header
    multi_wafer_plm_die_label.config(text=f"Die: X={x_coord}, Y={y_coord}", fg="blue")

    # Close old figures
    for ref in multi_wafer_plm_refs:
        try:
            if hasattr(ref, 'figure'):
                plt.close(ref.figure)
        except:
            pass

    # Clear existing content
    for widget in multi_wafer_plm_scrollable_frame.winfo_children():
        widget.destroy()
    multi_wafer_plm_refs.clear()

    # Get current filter
    current_filter = multi_wafer_plm_type_var.get()

    # Check if we have wafers loaded
    if not multi_wafer_wafer_configs or not multi_wafer_wafer_ids:
        tk.Label(
            multi_wafer_plm_scrollable_frame,
            text="No wafers loaded",
            font=("Helvetica", 9),
            fg="gray",
            bg="#e8e8e8"
        ).pack(pady=20)
        return

    # Collect PLM files from ALL wafers
    all_wafer_plm = []  # [(wafer_id, plm_files, plm_dir), ...]
    total_files = 0

    for i, (wafer_id, config) in enumerate(zip(multi_wafer_wafer_ids, multi_wafer_wafer_configs)):
        plm_dir = config.get('plm_dir')
        if plm_dir:
            files = find_plm_files_in_dir(x_coord, y_coord, plm_dir, current_filter)
            all_wafer_plm.append((wafer_id, files, plm_dir))
            total_files += len(files)
            print(f"  Wafer {wafer_id}: PLM dir={plm_dir}, found {len(files)} files")
        else:
            all_wafer_plm.append((wafer_id, [], None))
            print(f"  Wafer {wafer_id}: No PLM folder configured")

    if total_files == 0:
        tk.Label(
            multi_wafer_plm_scrollable_frame,
            text=f"No PLM files found\nfor die ({x_coord}, {y_coord})",
            font=("Helvetica", 9),
            fg="gray",
            bg="#e8e8e8"
        ).pack(pady=10)
        return

    # Display count
    tk.Label(
        multi_wafer_plm_scrollable_frame,
        text=f"{total_files} PLM file(s) from {len([w for w in all_wafer_plm if w[1]])} wafer(s)",
        font=("Helvetica", 8),
        fg="gray",
        bg="#e8e8e8"
    ).pack(pady=2)

    # Display PLM files for each wafer in horizontal rows
    for wafer_id, files, plm_dir in all_wafer_plm:
        if not files:
            continue

        # Wafer header
        wafer_header = tk.Frame(multi_wafer_plm_scrollable_frame, bg="#d0d0d0")
        wafer_header.pack(fill=tk.X, padx=2, pady=(5, 2))

        short_id = str(wafer_id)[:25] if len(str(wafer_id)) > 25 else str(wafer_id)
        tk.Label(
            wafer_header,
            text=f"📁 {short_id} ({len(files)} files)",
            font=("Helvetica", 8, "bold"),
            bg="#d0d0d0"
        ).pack(side=tk.LEFT, padx=5, pady=2)

        # Display each PLM file as a heatmap (same as Wafer tab)
        for plm_path in files:
            try:
                file_frame = tk.Frame(multi_wafer_plm_scrollable_frame, bg="#e8e8e8")
                file_frame.pack(pady=3, padx=3, fill=tk.X)

                plm_data = load_plm_as_matrix(plm_path)

                if plm_data is not None and plm_data.size > 0:
                    fig_plm, ax_plm = plt.subplots(figsize=(2.6, 2.0))
                    fig_plm.patch.set_facecolor('#e8e8e8')

                    im = ax_plm.imshow(plm_data, cmap='viridis', aspect='auto')

                    filename = os.path.basename(plm_path)
                    short_name = filename[:20] + "..." if len(filename) > 20 else filename
                    ax_plm.set_title(short_name, fontsize=7, fontweight="bold")
                    ax_plm.tick_params(axis='both', which='major', labelsize=5)

                    cbar = fig_plm.colorbar(im, ax=ax_plm, fraction=0.046, pad=0.04)
                    cbar.ax.tick_params(labelsize=5)

                    fig_plm.tight_layout()

                    plm_canvas_widget = FigureCanvasTkAgg(fig_plm, master=file_frame)
                    plm_canvas_widget.get_tk_widget().pack(fill=tk.BOTH, expand=True)
                    plm_canvas_widget.draw()

                    multi_wafer_plm_refs.append(plm_canvas_widget)

                    plm_canvas_widget.get_tk_widget().bind("<Button-1>",
                        lambda e, x=x_coord, y=y_coord: show_multi_wafer_plm_window(x, y))
                else:
                    # Fallback: show as link
                    filename = os.path.basename(plm_path)
                    if len(filename) > 30:
                        filename = filename[:27] + "..."
                    file_label = tk.Label(
                        file_frame,
                        text=f"📄 {filename}",
                        font=("Helvetica", 8),
                        bg="#e8e8e8",
                        fg="blue",
                        cursor="hand2"
                    )
                    file_label.pack(side=tk.LEFT, padx=2)
                    file_label.bind("<Button-1>", lambda e, path=plm_path: open_plm_file(path))

            except Exception as e:
                print(f"Error displaying PLM file {plm_path}: {e}")

    print(f"Displayed {total_files} PLM files for die ({x_coord}, {y_coord})")

