def update_multi_wafer_param_by_group():
    """Update multiwafer parameter combobox based on selected group"""
    global multi_wafer_test_params

    selected_group = multi_wafer_group_var.get()

    if not multi_wafer_test_params:
        return

    param_options = ["BIN (Bin Number)"]

    if selected_group == "All Groups" or selected_group not in grouped_parameters:
        # Show all parameters - sort by simplified parameter name
        for test_key, test_name in sorted(multi_wafer_test_params.items(), key=lambda x: simplify_param_name(x[1]).upper()):
            simple_name = simplify_param_name(test_name)
            param_options.append(f"{test_key}: {simple_name}")
    else:
        # Filter to selected group - show simplified parameter names
        if selected_group in grouped_parameters:
            params = grouped_parameters[selected_group]
            # Sort by simplified parameter name (alphabetically)
            for param in sorted(params, key=lambda x: simplify_param_name(x[2] if len(x) > 2 else x[1]).upper()):
                # Handle both 2-element and 3-element tuples
                test_num = param[0]
                full_name = param[2] if len(param) > 2 else param[1]
                simple_name = simplify_param_name(full_name)
                test_key = f"test_{test_num}"
                if test_key in multi_wafer_test_params:
                    param_options.append(f"{test_key}: {simple_name}")

    multi_wafer_param_combobox['values'] = param_options
    if param_options:
        multi_wafer_param_combobox.set(param_options[0])
        on_multi_wafer_param_changed()

