def _mw_ensure_charac_canvas():
    if _mw_charac_canvas_ref[0] is not None:
        return _mw_charac_canvas_ref[0]
    fig, ax = plt.subplots(figsize=(10, 6))
    fig.set_facecolor("#f5f5f5")
    ax.set_title("Characteristic Curve (Multi-Wafer)", fontsize=12)
    ax.grid(True, alpha=0.3)
    canvas = FigureCanvasTkAgg(fig, master=_mw_cc_plot_frame)
    canvas.get_tk_widget().pack(fill=tk.BOTH, expand=True)
    NavigationToolbar2Tk(canvas, _mw_cc_plot_frame).update()
    _mw_charac_canvas_ref[0] = (fig, ax, canvas)
    return fig, ax, canvas


def _mw_build_charac_param_list(group_name):
    """Build parameter list using multi_wafer_test_params and grouped_parameters."""
    params = ["BIN (Bin Number)"]
    if group_name == "\u2500\u2500\u2500 Custom Tests \u2500\u2500\u2500":
        try:
            for tn in sorted(custom_tests.keys()):
                params.append(f"CUSTOM: {tn}")
        except NameError:
            pass
    elif group_name == "All Groups" or not grouped_parameters:
        for tk_, tn in sorted(multi_wafer_test_params.items(), key=lambda x: simplify_param_name(x[1]).upper()):
            params.append(f"{tk_}: {simplify_param_name(tn)}")
    else:
        if group_name in grouped_parameters:
            gp = grouped_parameters[group_name]
            sp = sorted(gp, key=lambda x: simplify_param_name(x[2] if len(x) > 2 else x[1]).upper())
            for p in sp:
                tnum = p[0]
                fname = p[2] if len(p) > 2 else p[1]
                params.append(f"test_{tnum}: {simplify_param_name(fname)}")
    return params


def _mw_on_x_group_selected(event=None):
    params = _mw_build_charac_param_list(mw_charac_x_group_var.get())
    mw_charac_x_combo["values"] = params
    if params:
        mw_charac_x_combo.current(0)


def _mw_on_y_group_selected(event=None):
    params = _mw_build_charac_param_list(mw_charac_y_group_var.get())
    mw_charac_y_combo["values"] = params
    if params:
        mw_charac_y_combo.current(min(1, len(params) - 1))


mw_charac_x_group_combo.bind("<<ComboboxSelected>>", _mw_on_x_group_selected)
mw_charac_y_group_combo.bind("<<ComboboxSelected>>", _mw_on_y_group_selected)


def update_mw_charac_params():
    """Sync Multi-Wafer Charac.-Curve group comboboxes after loading wafers."""
    group_names = ["All Groups"]
    if grouped_parameters:
        group_names += sorted(grouped_parameters.keys())
    try:
        if custom_tests:
            group_names.append("\u2500\u2500\u2500 Custom Tests \u2500\u2500\u2500")
    except NameError:
        pass
    mw_charac_x_group_combo["values"] = group_names
    mw_charac_x_group_combo.current(0)
    mw_charac_y_group_combo["values"] = group_names
    mw_charac_y_group_combo.current(0)
    _mw_on_x_group_selected()
    _mw_on_y_group_selected()
    mw_charac_status_var.set(f"{len(multi_wafer_wafer_ids)} wafer(s) loaded.")


def _mw_get_cc_col(df, p):
    """Resolve parameter display string to DataFrame column (Multi-Wafer). Tries all naming conventions."""
    if p == "BIN (Bin Number)":
        for cand in ("BIN", "HARD_BIN", "SOFT_BIN", "HBR", "SBR", "bin", "Bin"):
            if cand in df.columns:
                return cand
        return None
    if p.startswith("CUSTOM: "):
        cname = p[8:]
        return cname if cname in df.columns else None
    if ":" in p:
        try:
            left = p.split(":")[0].strip()
            raw_left = left
            if left.startswith("test_"):
                left = left[5:]
            n = int(left)
            # Try: integer column
            if n in df.columns:
                return n
            # Try: float column that matches
            for c in df.columns:
                if isinstance(c, (int, float)) and int(c) == n:
                    return c
            # Try: "test_N" string column
            tn = f"test_{n}"
            if tn in df.columns:
                return tn
            # Try: raw left part as string (e.g. "test_12033010")
            if raw_left in df.columns:
                return raw_left
            # Try: string of the number
            sn = str(n)
            if sn in df.columns:
                return sn
            # Try: lookup original column name from multi_wafer_test_params dict
            tk = f"test_{n}"
            if tk in multi_wafer_test_params:
                orig = multi_wafer_test_params[tk]
                if orig in df.columns:
                    return orig
            # Try: search columns ending with the test number
            suffix = f"_{n}"
            for c in df.columns:
                if isinstance(c, str) and c.endswith(suffix):
                    return c
        except ValueError:
            pass
    # Fallback: exact match
    if p in df.columns:
        return p
    return None


def _mw_get_selected_wafer_indices():
    """Return indices of wafers selected via checkboxes in Multi-Wafer left panel."""
    selected = []
    for i, var in enumerate(multi_wafer_checkbox_vars):
        if i < len(multi_wafer_stdf_data) and var.get():
            selected.append(i)
    if not selected and multi_wafer_stdf_data:
        selected = list(range(len(multi_wafer_stdf_data)))
    return selected


def mw_plot_charac_curve():
    xp, yp = mw_charac_x_var.get(), mw_charac_y_var.get()
    print(f"[MW Charac] Plot requested: X='{xp}', Y='{yp}'")
    if not xp or not yp:
        mw_charac_status_var.set("Select X and Y parameters first.")
        return
    if not multi_wafer_stdf_data:
        mw_charac_status_var.set("No wafers loaded.")
        print(f"[MW Charac] No data in multi_wafer_stdf_data")
        return
    selected = _mw_get_selected_wafer_indices()
    print(f"[MW Charac] Selected wafer indices: {selected}, total wafers: {len(multi_wafer_stdf_data)}")
    if not selected:
        mw_charac_status_var.set("No wafers selected.")
        return
    fig, ax, canvas = _mw_ensure_charac_canvas()
    ax.clear()
    colors = plt.cm.tab10.colors
    total = 0
    skipped = 0
    pt = mw_charac_plot_type_var.get()
    for ci, idx in enumerate(selected):
        df = multi_wafer_stdf_data[idx]
        xc, yc = _mw_get_cc_col(df, xp), _mw_get_cc_col(df, yp)
        if ci == 0:
            print(f"[MW Charac] Wafer {idx} columns (first 20): {list(df.columns[:20])}")
            print(f"[MW Charac] Column types: {[type(c).__name__ for c in df.columns[:10]]}")
            print(f"[MW Charac] Resolved X='{xp}' -> col={xc}, Y='{yp}' -> col={yc}")
        if xc is None or yc is None:
            skipped += 1
            continue
        xd, yd = df[xc].dropna(), df[yc].dropna()
        common_idx = xd.index.intersection(yd.index)
        try:
            xv = xd.loc[common_idx].values.astype(float)
            yv = yd.loc[common_idx].values.astype(float)
        except (ValueError, TypeError) as e:
            print(f"[MW Charac] Float conversion failed for wafer {idx}: {e}")
            skipped += 1
            continue
        si = np.argsort(xv)
        xv, yv = xv[si], yv[si]
        c = colors[ci % len(colors)] if mw_charac_per_wafer_var.get() else colors[0]
        lb = multi_wafer_wafer_ids[idx] if idx < len(multi_wafer_wafer_ids) else f"Wafer {idx+1}"
        total += len(xv)
        if pt == "Scatter":
            ax.scatter(xv, yv, s=12, alpha=0.6, color=c, label=lb)
        elif pt == "Line":
            ax.plot(xv, yv, linewidth=1.2, alpha=0.8, color=c, label=lb)
        else:
            ax.scatter(xv, yv, s=10, alpha=0.5, color=c)
            ax.plot(xv, yv, linewidth=0.8, alpha=0.6, color=c, label=lb)
    if mw_charac_show_limits_var.get():
        try:
            left = yp.split(":")[0].strip()
            if left.startswith("test_"):
                left = left[5:]
            yt = int(left)
            if yt in test_limits:
                lm = test_limits[yt]
                if lm.get("lo_limit") is not None:
                    ax.axhline(y=float(lm["lo_limit"]), color="red", linestyle="--", linewidth=1, alpha=0.7, label=f"Lo: {lm['lo_limit']}")
                if lm.get("hi_limit") is not None:
                    ax.axhline(y=float(lm["hi_limit"]), color="red", linestyle="--", linewidth=1, alpha=0.7, label=f"Hi: {lm['hi_limit']}")
        except (ValueError, TypeError):
            pass
    ax.set_xlabel(xp, fontsize=9)
    ax.set_ylabel(yp, fontsize=9)
    ax.set_title(f"{yp}  vs  {xp}", fontsize=10, fontweight="bold")
    ax.grid(True, alpha=0.3)
    ax.legend(fontsize=8, loc="best")
    fig.tight_layout()
    canvas.draw()
    if total == 0:
        if skipped > 0:
            df0 = multi_wafer_stdf_data[selected[0]]
            cols_sample = [str(c) for c in list(df0.columns[:10])]
            mw_charac_status_var.set(f"0 points! Column not found. Cols: {', '.join(cols_sample)}...")
            print(f"[MW Charac] 0 points plotted. {skipped} wafers skipped (column not found).")
        else:
            mw_charac_status_var.set("0 points - no matching data found.")
    else:
        mw_charac_status_var.set(f"{total} points from {len(selected)} wafer(s)")


