def update_multi_wafer_stats_table():
    """Update the statistics table for Multi-Wafer tab - SIMPLE AND DIRECT"""
    global multi_wafer_stdf_data, multi_wafer_wafer_ids, grouped_parameters

    import numpy as np

    # Clear existing items
    for item in multi_wafer_stats_tree.get_children():
        multi_wafer_stats_tree.delete(item)

    if not multi_wafer_stdf_data or not multi_wafer_wafer_ids:
        multi_wafer_stats_summary_label.config(text="Keine Daten geladen.", fg="red")
        return

    # Get selected measures
    selected_measures = [key for key, var in multi_wafer_stats_measure_vars.items() if var.get()]
    if not selected_measures:
        multi_wafer_stats_summary_label.config(text="Bitte Kennzahlen auswählen.", fg="orange")
        return

    # ===== Hole ALLE numerischen Spalten aus dem ersten DataFrame =====
    first_df = multi_wafer_stdf_data[0]
    all_cols = first_df.select_dtypes(include=[np.number]).columns.tolist()

    # Exclude x, y, bin columns
    exclude = ['x', 'y', 'X', 'Y', 'bin', 'BIN', 'Bin']
    all_param_cols = [c for c in all_cols if c not in exclude]

    # ===== Gruppen-Filter anwenden =====
    selected_group = multi_wafer_stats_group_var.get()

    if selected_group and selected_group != "-- Gruppe auswählen --" and selected_group != "Alle":
        # Filter nach Gruppe
        param_cols = []
        for col in all_param_cols:
            col_str = str(col)
            detected_group = extract_group_from_column(col_str)
            if detected_group == selected_group:
                param_cols.append(col)

        if not param_cols:
            # Fallback: Zeige alle wenn keine gefunden
            param_cols = all_param_cols
            print(f"Keine Parameter für Gruppe '{selected_group}' gefunden, zeige alle")
    else:
        # Zeige alle Parameter
        param_cols = all_param_cols

    print(f"\n=== STATS TABLE: {len(param_cols)} von {len(all_param_cols)} Parametern (Gruppe: {selected_group}) ===")

    if not param_cols:
        multi_wafer_stats_summary_label.config(text="Keine Parameter gefunden.", fg="red")
        return

    # Setup tree columns: Parameter | Kennzahl | Wafer1 | Wafer2 | ...
    tree_cols = ["param", "stat"] + [f"w{i}" for i in range(len(multi_wafer_wafer_ids))]
    multi_wafer_stats_tree["columns"] = tree_cols
    multi_wafer_stats_tree["show"] = "headings"  # WICHTIG: Nur Headings zeigen!

    multi_wafer_stats_tree.heading("param", text="Parameter")
    multi_wafer_stats_tree.column("param", width=300, anchor="w")
    multi_wafer_stats_tree.heading("stat", text="Kennzahl")
    multi_wafer_stats_tree.column("stat", width=100, anchor="center")

    for i, wid in enumerate(multi_wafer_wafer_ids):
        cname = f"w{i}"
        short_wid = wid[:12] + "..." if len(wid) > 12 else wid
        multi_wafer_stats_tree.heading(cname, text=short_wid)
        multi_wafer_stats_tree.column(cname, width=90, anchor="center")

    # ===== Berechne Statistiken für jeden Parameter =====
    row_count = 0
    param_index = 0
    outlier_count = 0

    # Get outlier settings
    highlight_outliers = multi_wafer_stats_highlight_var.get()
    cv_threshold = multi_wafer_stats_cv_threshold_var.get()

    # Tags für abwechselnde Farben und Ausreißer konfigurieren
    multi_wafer_stats_tree.tag_configure('even_param', background='#f0f0f0')
    multi_wafer_stats_tree.tag_configure('odd_param', background='white')
    multi_wafer_stats_tree.tag_configure('outlier', background='#FFCDD2', foreground='#B71C1C')  # Rot für Ausreißer
    multi_wafer_stats_tree.tag_configure('outlier_even', background='#FFCDD2', foreground='#B71C1C')
    multi_wafer_stats_tree.tag_configure('outlier_odd', background='#FFEBEE', foreground='#B71C1C')

    # Pre-calculate CV for each parameter to detect outliers
    param_cv_values = {}
    for col in param_cols:
        all_vals = []
        for df in multi_wafer_stdf_data:
            if col in df.columns:
                vals = df[col].dropna().values
                all_vals.extend(vals)
        if len(all_vals) > 1:
            m = np.mean(all_vals)
            s = np.std(all_vals, ddof=1)
            if m != 0:
                param_cv_values[col] = (s / abs(m)) * 100
            else:
                param_cv_values[col] = 0
        else:
            param_cv_values[col] = 0

    for col in param_cols:
        # Extrahiere Test-Nummer aus Spaltennamen (z.B. _10021522 am Ende)
        import re
        test_num_match = re.search(r'_(\d{5,})$', str(col))
        test_num = test_num_match.group(1) if test_num_match else str(param_index + 1)

        # Verwende simplify_param_name für kürzere, lesbare Namen
        simple_name = simplify_param_name(str(col))
        col_name = f"test_{test_num}: {simple_name}"
        if len(col_name) > 55:
            col_name = col_name[:52] + "..."

        # Abwechselnde Farben pro Parameter
        row_tag = 'even_param' if param_index % 2 == 0 else 'odd_param'

        for mkey in selected_measures:
            # Get measure label
            mlabel = mkey
            for k, lbl, _ in multi_wafer_stats_measures_list:
                if k == mkey:
                    mlabel = lbl
                    break

            row = [col_name, mlabel]

            # Calculate stat for each wafer
            for df in multi_wafer_stdf_data:
                if col in df.columns:
                    vals = df[col].dropna().values
                    if len(vals) > 0:
                        # DIREKT berechnen!
                        try:
                            if mkey == "count":
                                row.append(f"{len(vals)}")
                            elif mkey == "mean":
                                row.append(f"{np.mean(vals):.4g}")
                            elif mkey == "median":
                                row.append(f"{np.median(vals):.4g}")
                            elif mkey == "std":
                                row.append(f"{np.std(vals, ddof=1):.4g}")
                            elif mkey == "min":
                                row.append(f"{np.min(vals):.4g}")
                            elif mkey == "max":
                                row.append(f"{np.max(vals):.4g}")
                            elif mkey == "range":
                                row.append(f"{np.max(vals) - np.min(vals):.4g}")
                            elif mkey == "cv":
                                m = np.mean(vals)
                                if m != 0:
                                    row.append(f"{(np.std(vals, ddof=1)/abs(m))*100:.2f}%")
                                else:
                                    row.append("-")
                            elif mkey == "sigma1":
                                m, s = np.mean(vals), np.std(vals, ddof=1)
                                row.append(f"{m-s:.3g}~{m+s:.3g}")
                            elif mkey == "sigma2":
                                m, s = np.mean(vals), np.std(vals, ddof=1)
                                row.append(f"{m-2*s:.3g}~{m+2*s:.3g}")
                            elif mkey == "sigma3":
                                m, s = np.mean(vals), np.std(vals, ddof=1)
                                row.append(f"{m-3*s:.3g}~{m+3*s:.3g}")
                            elif mkey == "p25":
                                row.append(f"{np.percentile(vals, 25):.4g}")
                            elif mkey == "p75":
                                row.append(f"{np.percentile(vals, 75):.4g}")
                            elif mkey == "p95":
                                row.append(f"{np.percentile(vals, 95):.4g}")
                            elif mkey == "iqr":
                                row.append(f"{np.percentile(vals, 75) - np.percentile(vals, 25):.4g}")
                            elif mkey == "skewness":
                                n = len(vals)
                                if n >= 3:
                                    m = np.mean(vals)
                                    s = np.std(vals, ddof=1)
                                    if s > 0:
                                        skew = np.mean(((vals - m) / s) ** 3)
                                        row.append(f"{skew:.4g}")
                                    else:
                                        row.append("-")
                                else:
                                    row.append("-")
                            elif mkey == "kurtosis":
                                n = len(vals)
                                if n >= 4:
                                    m = np.mean(vals)
                                    s = np.std(vals, ddof=1)
                                    if s > 0:
                                        kurt = np.mean(((vals - m) / s) ** 4) - 3
                                        row.append(f"{kurt:.4g}")
                                    else:
                                        row.append("-")
                                else:
                                    row.append("-")
                            else:
                                row.append("-")
                        except Exception as e:
                            row.append("-")
                    else:
                        row.append("-")
                else:
                    row.append("-")

            # Determine if this is an outlier (CV > threshold)
            is_outlier = highlight_outliers and param_cv_values.get(col, 0) > cv_threshold

            if is_outlier:
                row_tag = 'outlier_even' if param_index % 2 == 0 else 'outlier_odd'
                outlier_count += 1
            else:
                row_tag = 'even_param' if param_index % 2 == 0 else 'odd_param'

            multi_wafer_stats_tree.insert("", "end", values=row, tags=(row_tag,))
            row_count += 1

        param_index += 1  # Nächster Parameter

    print(f"=== STATS TABLE: {row_count} rows inserted, {outlier_count} outliers ===")
    group_text = f"Gruppe: {selected_group} | " if selected_group and selected_group != "-- Gruppe auswählen --" else ""
    outlier_text = f" | 🔴 {outlier_count} auffällig" if outlier_count > 0 and highlight_outliers else ""
    multi_wafer_stats_summary_label.config(
        text=f"{group_text}{len(param_cols)} Parameter | {row_count} Zeilen{outlier_text}",
        fg="red" if outlier_count > 0 else "green"
    )

def calculate_statistic(values, measure_key):
    """Calculate a specific statistic for the given values"""
    try:
        import numpy as np
        from scipy import stats as scipy_stats

        if len(values) == 0:
            return "-"

        if measure_key == "count":
            return f"{len(values)}"
        elif measure_key == "mean":
            return f"{np.mean(values):.4g}"
        elif measure_key == "median":
            return f"{np.median(values):.4g}"
        elif measure_key == "std":
            return f"{np.std(values, ddof=1):.4g}"
        elif measure_key == "min":
            return f"{np.min(values):.4g}"
        elif measure_key == "max":
            return f"{np.max(values):.4g}"
        elif measure_key == "range":
            return f"{np.max(values) - np.min(values):.4g}"
        elif measure_key == "cv":
            mean_val = np.mean(values)
            if mean_val != 0:
                cv = (np.std(values, ddof=1) / abs(mean_val)) * 100
                return f"{cv:.2f}%"
            return "-"
        elif measure_key == "sigma1":
            mean = np.mean(values)
            std = np.std(values, ddof=1)
            return f"{mean-std:.4g} - {mean+std:.4g}"
        elif measure_key == "sigma2":
            mean = np.mean(values)
            std = np.std(values, ddof=1)
            return f"{mean-2*std:.4g} - {mean+2*std:.4g}"
        elif measure_key == "sigma3":
            mean = np.mean(values)
            std = np.std(values, ddof=1)
            return f"{mean-3*std:.4g} - {mean+3*std:.4g}"
        elif measure_key == "p25":
            return f"{np.percentile(values, 25):.4g}"
        elif measure_key == "p75":
            return f"{np.percentile(values, 75):.4g}"
        elif measure_key == "p95":
            return f"{np.percentile(values, 95):.4g}"
        elif measure_key == "iqr":
            return f"{np.percentile(values, 75) - np.percentile(values, 25):.4g}"
        elif measure_key == "skewness":
            if len(values) >= 3:
                return f"{scipy_stats.skew(values):.4g}"
            return "-"
        elif measure_key == "kurtosis":
            if len(values) >= 4:
                return f"{scipy_stats.kurtosis(values):.4g}"
            return "-"
        else:
            return "-"
    except Exception as e:
        return "-"

