def export_multi_wafer_stats_table():
    """Export the Multi-Wafer statistics table to CSV or Excel"""
    items = multi_wafer_stats_tree.get_children()
    if not items:
        from tkinter import messagebox
        messagebox.showwarning("Export", "Keine Daten zum Exportieren. Bitte laden Sie Daten und wählen Sie eine Gruppe.")
        return

    # Get column headers
    columns = multi_wafer_stats_tree["columns"]
    headers = [multi_wafer_stats_tree.heading(col)["text"] for col in columns]

    # Collect data
    data = []
    for item in items:
        values = multi_wafer_stats_tree.item(item, "values")
        data.append(values)

    # Ask for save location
    from datetime import datetime
    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    group_name = multi_wafer_stats_group_var.get().replace(" ", "_").replace("/", "_")[:20]
    default_filename = f"Statistics_{group_name}_{timestamp}"

    filepath = filedialog.asksaveasfilename(
        title="Export Statistik-Tabelle",
        defaultextension=".csv",
        initialfile=default_filename,
        filetypes=[
            ("CSV files", "*.csv"),
            ("Excel files", "*.xlsx"),
            ("All files", "*.*")
        ]
    )

    if not filepath:
        return

    try:
        if filepath.endswith(".xlsx"):
            df = pd.DataFrame(data, columns=headers)
            df.to_excel(filepath, index=False, sheet_name="Statistik")
            print(f"Exported to Excel: {filepath}")
        else:
            df = pd.DataFrame(data, columns=headers)
            df.to_csv(filepath, index=False, encoding='utf-8-sig')
            print(f"Exported to CSV: {filepath}")

        from tkinter import messagebox
        messagebox.showinfo("Export erfolgreich", f"Statistiktabelle exportiert nach:\n{filepath}")
    except Exception as e:
        from tkinter import messagebox
        messagebox.showerror("Export Fehler", f"Export fehlgeschlagen: {str(e)}")
        print(f"Export error: {e}")

