def update_diffmap_wafer_overview():
    """Update the wafer overview panel with loaded data information"""
    global diffmap_reference_data, diffmap_compare_data, diffmap_reference_path, diffmap_compare_path
    global diffmap_reference_id, diffmap_compare_id, diffmap_result_data

    # Update Reference Wafer info
    if diffmap_reference_path:
        filename = os.path.basename(diffmap_reference_path)
        short_name = filename[:20] + "..." if len(filename) > 20 else filename
        diffmap_ref_file_value.config(text=short_name, fg="darkgreen")

        if diffmap_reference_data is not None and not diffmap_reference_data.empty:
            diffmap_ref_waferid_value.config(text=diffmap_reference_id if diffmap_reference_id else "-", fg="black")
            diffmap_ref_dies_value.config(text=str(len(diffmap_reference_data)), fg="black")
            num_params = len([c for c in diffmap_reference_data.columns if c not in ['x', 'y', 'bin', 'sbin', 'hbin']])
            diffmap_ref_params_value.config(text=str(num_params), fg="black")
        else:
            diffmap_ref_waferid_value.config(text="Ausstehend...", fg="orange")
            diffmap_ref_dies_value.config(text="-", fg="gray")
            diffmap_ref_params_value.config(text="-", fg="gray")
    else:
        diffmap_ref_file_value.config(text="Nicht geladen", fg="gray")
        diffmap_ref_waferid_value.config(text="-", fg="gray")
        diffmap_ref_dies_value.config(text="-", fg="gray")
        diffmap_ref_params_value.config(text="-", fg="gray")

    # Update Comparison Wafer info
    if diffmap_compare_path:
        filename = os.path.basename(diffmap_compare_path)
        short_name = filename[:20] + "..." if len(filename) > 20 else filename
        diffmap_comp_file_value.config(text=short_name, fg="darkorange")

        if diffmap_compare_data is not None and not diffmap_compare_data.empty:
            diffmap_comp_waferid_value.config(text=diffmap_compare_id if diffmap_compare_id else "-", fg="black")
            diffmap_comp_dies_value.config(text=str(len(diffmap_compare_data)), fg="black")
            num_params = len([c for c in diffmap_compare_data.columns if c not in ['x', 'y', 'bin', 'sbin', 'hbin']])
            diffmap_comp_params_value.config(text=str(num_params), fg="black")
        else:
            diffmap_comp_waferid_value.config(text="Ausstehend...", fg="orange")
            diffmap_comp_dies_value.config(text="-", fg="gray")
            diffmap_comp_params_value.config(text="-", fg="gray")
    else:
        diffmap_comp_file_value.config(text="Nicht geladen", fg="gray")
        diffmap_comp_waferid_value.config(text="-", fg="gray")
        diffmap_comp_dies_value.config(text="-", fg="gray")
        diffmap_comp_params_value.config(text="-", fg="gray")

    # Update Diff Summary
    if diffmap_result_data is not None and len(diffmap_result_data) > 0:
        diffmap_common_dies_value.config(text=str(len(diffmap_result_data)), fg="black")

        # Get selected parameter for diff stats
        try:
            selected_param = diffmap_param_combobox.get()
            if selected_param and selected_param != "Select Parameter" and selected_param in diffmap_result_data.columns:
                diff_values = diffmap_result_data[selected_param].dropna()
                if len(diff_values) > 0:
                    diffmap_diff_min_value.config(text=f"{diff_values.min():.4g}", fg="blue")
                    diffmap_diff_max_value.config(text=f"{diff_values.max():.4g}", fg="red")
                    diffmap_diff_mean_value.config(text=f"{diff_values.mean():.4g}", fg="black")
                    diffmap_diff_std_value.config(text=f"{diff_values.std():.4g}", fg="black")
                else:
                    diffmap_diff_min_value.config(text="-", fg="gray")
                    diffmap_diff_max_value.config(text="-", fg="gray")
                    diffmap_diff_mean_value.config(text="-", fg="gray")
                    diffmap_diff_std_value.config(text="-", fg="gray")
            else:
                diffmap_diff_min_value.config(text="-", fg="gray")
                diffmap_diff_max_value.config(text="-", fg="gray")
                diffmap_diff_mean_value.config(text="-", fg="gray")
                diffmap_diff_std_value.config(text="-", fg="gray")
        except:
            pass

