def draw_wafermap_preview(slide_index=0):
    """Draw the interactive preview for Wafermap tab (backward compatible)"""
    data = wafermap_multi_slide_data.get(slide_index)
    if not data:
        return
    canvas = data["canvas"]
    layout_boxes = data["layout_boxes"]
    enable_vars = data["enable_vars"]
    scale = data.get("scale", WAFERMAP_BASE_SCALE)

    canvas.delete("all")
    slide_w = int(13.333 * scale)
    slide_h = int(7.5 * scale)
    canvas.config(width=slide_w, height=slide_h)
    canvas.create_rectangle(2, 2, slide_w-2, slide_h-2, fill="#F5F5F5", outline="#CCCCCC", width=2)

    # Draw grid
    for i in range(1, 13):
        x = i * scale
        canvas.create_line(x, 0, x, slide_h, fill="#EEEEEE", dash=(2, 4))
    for i in range(1, 7):
        y = i * scale
        canvas.create_line(0, y, slide_w, y, fill="#EEEEEE", dash=(2, 4))

    for box_name, box_data in layout_boxes.items():
        if not enable_vars.get(box_name, tk.BooleanVar(value=True)).get():
            continue
        x = box_data["x"] * scale
        y = box_data["y"] * scale
        w = box_data["width"] * scale
        h = box_data["height"] * scale
        canvas.create_rectangle(x, y, x+w, y+h, fill=box_data["fill"], outline=box_data["color"], width=2, tags=(f"box_{box_name}", "box", "movable"))
        font_size = max(6, int(scale / 5))
        canvas.create_text(x+w/2, y+h/2, text=box_data["label"], font=("Helvetica", font_size, "bold"), fill=box_data["color"], tags=(f"label_{box_name}",))
        # Resize handle
        handle_size = max(10, int(scale / 2.5))
        canvas.create_rectangle(x+w-handle_size, y+h-handle_size, x+w, y+h, fill=box_data["color"], outline="white", width=2, tags=(f"handle_{box_name}", "handle"))
        canvas.create_line(x+w-handle_size+4, y+h-4, x+w-4, y+h-handle_size+4, fill="white", width=2, tags=(f"handle_{box_name}",))
        # Dimensions
        canvas.create_text(x+w/2, y+h+10, text=f"{box_data['width']:.1f}\" × {box_data['height']:.1f}\"", font=("Helvetica", max(5, int(scale/6))), fill="#888888")

