# Storage for multiple slide configurations
multi_wafer_multi_slide_data = {}

# PowerPoint slide dimensions (13.333 x 7.5 inches - standard 16:9)
PPTX_SLIDE_WIDTH = 13.333
PPTX_SLIDE_HEIGHT = 7.5
MULTI_WAFER_BASE_SCALE = 38
PREVIEW_SCALE = MULTI_WAFER_BASE_SCALE

# Default layout boxes configuration
pptx_default_layout_boxes = {
    "title": {"x": 0.3, "y": 0.15, "width": 12.733, "height": 0.5, "color": "#1976D2", "fill": "#E3F2FD", "enabled": True, "label": "Title"},
    "wafermap": {"x": 0.3, "y": 0.7, "width": 6.0, "height": 6.0, "color": "#4CAF50", "fill": "#E8F5E9", "enabled": True, "label": "Wafermap"},
    "boxplot": {"x": 6.5, "y": 0.7, "width": 6.5, "height": 3.0, "color": "#FF9800", "fill": "#FFF3E0", "enabled": True, "label": "Boxplot"},
    "histogram": {"x": 6.5, "y": 3.8, "width": 6.5, "height": 2.9, "color": "#9C27B0", "fill": "#F3E5F5", "enabled": True, "label": "Histogram"},
    "stats": {"x": 0.3, "y": 6.8, "width": 12.733, "height": 0.5, "color": "#607D8B", "fill": "#ECEFF1", "enabled": False, "label": "Statistics"},
    "summary": {"x": 0.3, "y": 6.8, "width": 6.0, "height": 0.5, "color": "#E91E63", "fill": "#FCE4EC", "enabled": False, "label": "Summary"},
}

# Keep backward compatibility
pptx_layout_boxes = {k: dict(v) for k, v in pptx_default_layout_boxes.items()}

# Variables to track drag state
preview_drag_data = {"item": None, "x": 0, "y": 0, "mode": None, "box_name": None, "slide_index": 0}

def calculate_multi_wafer_preview_scale(container_frame):
    """Calculate optimal preview scale based on container size"""
    container_frame.update_idletasks()
    available_width = container_frame.winfo_width() - 20
    available_height = container_frame.winfo_height() - 100
    if available_width < 100 or available_height < 100:
        return MULTI_WAFER_BASE_SCALE
    scale_x = available_width / 13.333
    scale_y = available_height / 7.5
    optimal_scale = min(scale_x, scale_y)
    return max(25, min(optimal_scale, 60))

def create_multi_wafer_slide_tab(slide_index):
    """Create a new slide tab with its own layout preview"""
    global multi_wafer_multi_slide_data

    tab_frame = ttk.Frame(multi_wafer_slides_notebook)
    multi_wafer_slides_notebook.add(tab_frame, text=f"Folie {slide_index + 1}")

    slide_layout_boxes = {k: dict(v) for k, v in pptx_default_layout_boxes.items()}

    canvas_frame = tk.Frame(tab_frame)
    canvas_frame.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)

    current_scale = PREVIEW_SCALE

    preview_canvas = tk.Canvas(
        canvas_frame,
        width=int(PPTX_SLIDE_WIDTH * current_scale),
        height=int(PPTX_SLIDE_HEIGHT * current_scale),
        bg="white",
        relief="solid",
        bd=1
    )
    preview_canvas.pack(pady=5, expand=True)

    box_enable_frame = tk.LabelFrame(tab_frame, text="Elemente ein-/ausblenden", font=("Helvetica", 9))
    box_enable_frame.pack(fill=tk.X, padx=5, pady=5)

    box_enable_vars = {}
    for box_name, box_data in slide_layout_boxes.items():
        var = tk.BooleanVar(value=box_data["enabled"])
        box_enable_vars[box_name] = var

    multi_wafer_multi_slide_data[slide_index] = {
        "tab_frame": tab_frame,
        "canvas_frame": canvas_frame,
        "layout_boxes": slide_layout_boxes,
        "canvas": preview_canvas,
        "enable_vars": box_enable_vars,
        "enable_frame": box_enable_frame,
        "scale": current_scale
    }

    def draw_slide_preview(idx=slide_index):
        data = multi_wafer_multi_slide_data.get(idx)
        if not data:
            return
        canvas = data["canvas"]
        layout_boxes = data["layout_boxes"]
        enable_vars = data["enable_vars"]
        scale = data.get("scale", MULTI_WAFER_BASE_SCALE)

        canvas.delete("all")
        slide_w = int(PPTX_SLIDE_WIDTH * scale)
        slide_h = int(PPTX_SLIDE_HEIGHT * scale)
        canvas.config(width=slide_w, height=slide_h)
        canvas.create_rectangle(2, 2, slide_w-2, slide_h-2, fill="#F5F5F5", outline="#CCCCCC", width=2)

        for i in range(1, 13):
            x = i * scale
            canvas.create_line(x, 0, x, slide_h, fill="#EEEEEE", dash=(2, 4))
        for i in range(1, 7):
            y = i * scale
            canvas.create_line(0, y, slide_w, y, fill="#EEEEEE", dash=(2, 4))

        for box_name, box_data in layout_boxes.items():
            if not enable_vars.get(box_name, tk.BooleanVar(value=True)).get():
                continue
            x = box_data["x"] * scale
            y = box_data["y"] * scale
            w = box_data["width"] * scale
            h = box_data["height"] * scale
            canvas.create_rectangle(x, y, x+w, y+h, fill=box_data["fill"], outline=box_data["color"], width=2, tags=(f"box_{box_name}", "box", "movable"))
            font_size = max(6, int(scale / 5))
            canvas.create_text(x+w/2, y+h/2, text=box_data["label"], font=("Helvetica", font_size, "bold"), fill=box_data["color"], tags=(f"label_{box_name}",))
            handle_size = max(12, int(scale / 2))
            canvas.create_rectangle(x+w-handle_size, y+h-handle_size, x+w, y+h, fill=box_data["color"], outline="white", width=2, tags=(f"handle_{box_name}", "handle"))
            canvas.create_line(x+w-handle_size+4, y+h-4, x+w-4, y+h-handle_size+4, fill="white", width=2, tags=(f"handle_{box_name}",))
            canvas.create_text(x+w/2, y+h+10, text=f"{box_data['width']:.1f}\" × {box_data['height']:.1f}\"", font=("Helvetica", max(5, int(scale/6))), fill="#888888")

    def on_slide_press(event, idx=slide_index):
        global preview_drag_data
        data = multi_wafer_multi_slide_data.get(idx)
        if not data:
            return
        canvas = data["canvas"]
        layout_boxes = data["layout_boxes"]

        handle_items = canvas.find_overlapping(event.x-10, event.y-10, event.x+10, event.y+10)
        for item in handle_items:
            tags = canvas.gettags(item)
            for tag in tags:
                if tag.startswith("handle_"):
                    box_name = tag.replace("handle_", "")
                    if box_name in layout_boxes:
                        preview_drag_data = {"item": item, "x": event.x, "y": event.y, "mode": "resize", "box_name": box_name, "slide_index": idx}
                        canvas.config(cursor="bottom_right_corner")
                        return
        items = canvas.find_overlapping(event.x-2, event.y-2, event.x+2, event.y+2)
        for item in items:
            tags = canvas.gettags(item)
            if "movable" in tags:
                for tag in tags:
                    if tag.startswith("box_") and not tag.startswith("box_name"):
                        box_name = tag.replace("box_", "")
                        if box_name in layout_boxes:
                            preview_drag_data = {"item": item, "x": event.x, "y": event.y, "mode": "move", "box_name": box_name, "slide_index": idx}
                            canvas.config(cursor="fleur")
                            return

    def on_slide_drag(event, idx=slide_index):
        global preview_drag_data
        if preview_drag_data.get("slide_index") != idx:
            return
        if preview_drag_data["box_name"] is None:
            return
        data = multi_wafer_multi_slide_data.get(idx)
        if not data:
            return
        layout_boxes = data["layout_boxes"]
        scale = data.get("scale", MULTI_WAFER_BASE_SCALE)
        box_name = preview_drag_data["box_name"]
        dx = event.x - preview_drag_data["x"]
        dy = event.y - preview_drag_data["y"]
        dx_inches = dx / scale
        dy_inches = dy / scale
        if preview_drag_data["mode"] == "move":
            new_x = max(0, min(PPTX_SLIDE_WIDTH - layout_boxes[box_name]["width"], layout_boxes[box_name]["x"] + dx_inches))
            new_y = max(0, min(PPTX_SLIDE_HEIGHT - layout_boxes[box_name]["height"], layout_boxes[box_name]["y"] + dy_inches))
            layout_boxes[box_name]["x"] = round(new_x, 2)
            layout_boxes[box_name]["y"] = round(new_y, 2)
        elif preview_drag_data["mode"] == "resize":
            new_w = max(0.5, min(PPTX_SLIDE_WIDTH - layout_boxes[box_name]["x"], layout_boxes[box_name]["width"] + dx_inches))
            new_h = max(0.3, min(PPTX_SLIDE_HEIGHT - layout_boxes[box_name]["y"], layout_boxes[box_name]["height"] + dy_inches))
            layout_boxes[box_name]["width"] = round(new_w, 2)
            layout_boxes[box_name]["height"] = round(new_h, 2)
        preview_drag_data["x"] = event.x
        preview_drag_data["y"] = event.y
        draw_slide_preview(idx)

    def on_slide_release(event, idx=slide_index):
        global preview_drag_data
        data = multi_wafer_multi_slide_data.get(idx)
        if data:
            data["canvas"].config(cursor="")
        preview_drag_data = {"item": None, "x": 0, "y": 0, "mode": None, "box_name": None, "slide_index": 0}

    preview_canvas.bind("<ButtonPress-1>", lambda e, i=slide_index: on_slide_press(e, i))
    preview_canvas.bind("<B1-Motion>", lambda e, i=slide_index: on_slide_drag(e, i))
    preview_canvas.bind("<ButtonRelease-1>", lambda e, i=slide_index: on_slide_release(e, i))

    for box_name, box_data in slide_layout_boxes.items():
        cb = tk.Checkbutton(
            box_enable_frame,
            text=box_data["label"],
            variable=box_enable_vars[box_name],
            font=("Helvetica", 8),
            fg=box_data["color"],
            command=lambda i=slide_index: draw_slide_preview(i)
        )
        cb.pack(side=tk.LEFT, padx=3)

    preset_frame = tk.Frame(tab_frame)
    preset_frame.pack(fill=tk.X, padx=5, pady=5)

    def apply_slide_preset(preset, idx=slide_index):
        data = multi_wafer_multi_slide_data.get(idx)
        if not data:
            return
        layout_boxes = data["layout_boxes"]
        presets = {
            "Standard": {"title": (0.3, 0.15, 12.733, 0.5), "wafermap": (0.3, 0.7, 6.0, 6.0), "boxplot": (6.5, 0.7, 6.5, 3.0), "histogram": (6.5, 3.8, 6.5, 2.9), "stats": (0.3, 6.8, 12.733, 0.5)},
            "Full Image": {"title": (0.3, 0.15, 12.733, 0.5), "wafermap": (0.3, 0.7, 12.7, 6.5), "boxplot": (0.3, 0.7, 12.7, 6.5), "histogram": (0.3, 0.7, 12.7, 6.5), "stats": (0.3, 6.8, 12.733, 0.5)},
            "2x2 Grid": {"title": (0.3, 0.15, 12.733, 0.5), "wafermap": (0.3, 0.7, 6.3, 3.2), "boxplot": (6.7, 0.7, 6.3, 3.2), "histogram": (0.3, 4.0, 6.3, 3.2), "stats": (6.7, 4.0, 6.3, 3.2)},
            "Side by Side": {"title": (0.3, 0.15, 12.733, 0.5), "wafermap": (0.3, 0.7, 4.2, 6.5), "boxplot": (4.6, 0.7, 4.2, 6.5), "histogram": (8.9, 0.7, 4.2, 6.5), "stats": (0.3, 6.8, 12.733, 0.5)},
        }
        if preset in presets:
            for box_name, vals in presets[preset].items():
                if box_name in layout_boxes:
                    layout_boxes[box_name]["x"], layout_boxes[box_name]["y"] = vals[0], vals[1]
                    layout_boxes[box_name]["width"], layout_boxes[box_name]["height"] = vals[2], vals[3]
            draw_slide_preview(idx)

    tk.Label(preset_frame, text="Presets:", font=("Helvetica", 8, "bold")).pack(side=tk.LEFT, padx=2)
    for preset in ["Standard", "Full Image", "2x2 Grid", "Side by Side"]:
        tk.Button(preset_frame, text=preset, font=("Helvetica", 7), command=lambda p=preset, i=slide_index: apply_slide_preset(p, i)).pack(side=tk.LEFT, padx=2)

    tk.Label(tab_frame, text="💡 Ziehen = Verschieben, Ecke = Größe ändern", font=("Helvetica", 7), fg="#666666").pack(pady=2)

    def on_canvas_resize(event, idx=slide_index):
        data = multi_wafer_multi_slide_data.get(idx)
        if not data:
            return
        new_scale = calculate_multi_wafer_preview_scale(data["canvas_frame"])
        if abs(new_scale - data.get("scale", MULTI_WAFER_BASE_SCALE)) > 2:
            data["scale"] = new_scale
            draw_slide_preview(idx)

    canvas_frame.bind("<Configure>", lambda e, i=slide_index: on_canvas_resize(e, i))

    draw_slide_preview(slide_index)

    return slide_index

def update_multi_wafer_slide_tabs(*args):
    """Update the number of slide tabs based on spinbox value"""
    global multi_wafer_multi_slide_data
    target_count = multi_wafer_slide_count_var.get()
    current_count = len(multi_wafer_multi_slide_data)

    while current_count < target_count:
        create_multi_wafer_slide_tab(current_count)
        current_count += 1

    while current_count > target_count:
        current_count -= 1
        if current_count in multi_wafer_multi_slide_data:
            tab_frame = multi_wafer_multi_slide_data[current_count]["tab_frame"]
            multi_wafer_slides_notebook.forget(tab_frame)
            del multi_wafer_multi_slide_data[current_count]

multi_wafer_slide_count_var.trace_add("write", update_multi_wafer_slide_tabs)

# Create initial slide tab
create_multi_wafer_slide_tab(0)

