def add_param_to_report():
    """Add selected parameter to the report list"""
    global pptx_selected_params_for_report, grouped_parameters

    group = pptx_report_group_var.get()
    param = pptx_report_param_var.get()

    if group == "-- Select Group --" or param == "-- Select Parameter --":
        return

    # Extract test number from param string (format: "test_XXXX: ParamName")
    if ":" in param:
        test_key = param.split(":")[0].strip()
        param_name = param.split(":", 1)[1].strip() if ":" in param else param
    else:
        test_key = param
        param_name = param

    # Check if already in list
    entry = {"group": group, "test_key": test_key, "param_name": param_name, "display": f"{group} > {param_name}"}

    # Avoid duplicates
    for existing in pptx_selected_params_for_report:
        if existing["test_key"] == test_key:
            return

    pptx_selected_params_for_report.append(entry)
    pptx_selected_params_listbox.insert(tk.END, entry["display"])

def remove_param_from_report():
    """Remove selected parameter from the report list"""
    global pptx_selected_params_for_report

    selection = pptx_selected_params_listbox.curselection()
    if not selection:
        return

    idx = selection[0]
    pptx_selected_params_listbox.delete(idx)
    if idx < len(pptx_selected_params_for_report):
        pptx_selected_params_for_report.pop(idx)

def clear_params_from_report():
    """Clear all parameters from the report list"""
    global pptx_selected_params_for_report
    pptx_selected_params_for_report = []
    pptx_selected_params_listbox.delete(0, tk.END)

