def update_pptx_report_group_combobox():
    """Update all parameter group comboboxes in Report tab with available groups from loaded data"""
    global grouped_parameters

    print(f"DEBUG update_pptx_report_group_combobox: grouped_parameters has {len(grouped_parameters) if grouped_parameters else 0} groups")

    groups = ["-- Select Group --"]
    if grouped_parameters:
        groups.extend(sorted(grouped_parameters.keys()))
        print(f"DEBUG: Adding {len(grouped_parameters)} groups to Report combobox: {list(grouped_parameters.keys())[:5]}...")

    # Multiple Wafermaps tab
    pptx_report_group_combobox["values"] = groups
    pptx_report_group_combobox.set("-- Select Group --")
    pptx_report_param_combobox["values"] = ["-- Select Parameter --"]
    pptx_report_param_combobox.set("-- Select Parameter --")
    print(f"DEBUG: Report group combobox now has {len(groups)} values")

    # Wafermap tab
    try:
        pptx_wafermap_report_group_combobox["values"] = groups
        pptx_wafermap_report_group_combobox.set("-- Select Group --")
        pptx_wafermap_report_param_combobox["values"] = ["-- Select Parameter --"]
        pptx_wafermap_report_param_combobox.set("-- Select Parameter --")
    except NameError:
        pass

    # Diffmap tab
    try:
        pptx_diffmap_report_group_combobox["values"] = groups
        pptx_diffmap_report_group_combobox.set("-- Select Group --")
        pptx_diffmap_report_param_combobox["values"] = ["-- Select Parameter --"]
        pptx_diffmap_report_param_combobox.set("-- Select Parameter --")
    except NameError:
        pass

    # Gage R&R tab - populate group data for multi-group selection
    try:
        populate_grr_group_data()
    except NameError:
        pass

    # Statistics Table tab (in Report)
    try:
        stats_groups = ["-- Gruppe auswählen --"]
        if grouped_parameters:
            stats_groups.extend(sorted(grouped_parameters.keys()))
        stats_table_group_combobox["values"] = stats_groups
        stats_table_group_combobox.set("-- Gruppe auswählen --")
    except NameError:
        pass

    # Multi-Wafer Statistics Table tab
    try:
        update_multi_wafer_stats_group_combo()
    except NameError:
        pass

    # Diffmap Statistics Table tab
    try:
        update_diffmap_stats_group_combo()
    except NameError:
        pass

def on_pptx_report_group_selected(event=None):
    """When a group is selected, update the parameter combobox with parameters from that group"""
    global grouped_parameters

    selected_group = pptx_report_group_var.get()

    if selected_group == "-- Select Group --" or not grouped_parameters:
        pptx_report_param_combobox["values"] = ["-- Select Parameter --"]
        pptx_report_param_combobox.set("-- Select Parameter --")
        return

    if selected_group in grouped_parameters:
        params = grouped_parameters[selected_group]
        # Format: list of (test_num, short_name, full_name)
        param_options = [f"test_{test_num}: {short_name}" for test_num, short_name, full_name in params]
        pptx_report_param_combobox["values"] = ["-- Select Parameter --"] + param_options
        pptx_report_param_combobox.set("-- Select Parameter --")
    else:
        pptx_report_param_combobox["values"] = ["-- Select Parameter --"]
        pptx_report_param_combobox.set("-- Select Parameter --")

# Bind the group selection event
pptx_report_group_combobox.bind("<<ComboboxSelected>>", on_pptx_report_group_selected)

