def remove_diffmap_param_from_report():
    """Remove selected parameter from diffmap report list"""
    global pptx_diffmap_selected_params

    selection = pptx_diffmap_params_listbox.curselection()
    if not selection:
        return

    idx = selection[0]
    pptx_diffmap_params_listbox.delete(idx)
    if idx < len(pptx_diffmap_selected_params):
        pptx_diffmap_selected_params.pop(idx)

