def generate_stats_table():
    """Generate statistics table for the selected parameter group"""
    global grouped_parameters, multi_wafer_stdf_data, multi_wafer_wafer_ids, current_stdf_data, current_wafer_id
    from scipy import stats as scipy_stats

    selected_group = stats_table_group_var.get()
    if selected_group == "-- Gruppe auswählen --":
        return

    # Determine data sources - use multi_wafer data (correct global variable name)
    if multi_wafer_stdf_data and len(multi_wafer_stdf_data) > 0:
        data_sources = multi_wafer_stdf_data
        wafer_labels = multi_wafer_wafer_ids if multi_wafer_wafer_ids else [f"Wafer {i+1}" for i in range(len(multi_wafer_stdf_data))]
    elif current_stdf_data is not None and not current_stdf_data.empty:
        data_sources = [current_stdf_data]
        wafer_labels = [current_wafer_id if current_wafer_id else "Wafer 1"]
    else:
        return

    if selected_group not in grouped_parameters:
        return

    params = grouped_parameters[selected_group]

    # Clear existing table
    for widget in stats_table_frame.winfo_children():
        widget.destroy()

    # Create header row
    headers = ["Parameter"]
    for wafer_label in wafer_labels:
        short_label = str(wafer_label)[:15] + "..." if len(str(wafer_label)) > 15 else str(wafer_label)
        headers.append(short_label)

    # Get selected measures
    selected_measures = [key for key, var in stats_measures_vars.items() if var.get()]

    # Create Treeview for table
    columns = headers
    stats_tree = ttk.Treeview(stats_table_frame, columns=columns, show='headings', height=20)

    # Configure columns
    stats_tree.column(headers[0], width=200, minwidth=150)
    for col in headers[1:]:
        stats_tree.column(col, width=100, minwidth=80, anchor='center')

    for col in headers:
        stats_tree.heading(col, text=col)

    # Add scrollbars
    stats_tree_scroll_y = ttk.Scrollbar(stats_table_frame, orient="vertical", command=stats_tree.yview)
    stats_tree_scroll_x = ttk.Scrollbar(stats_table_frame, orient="horizontal", command=stats_tree.xview)
    stats_tree.configure(yscrollcommand=stats_tree_scroll_y.set, xscrollcommand=stats_tree_scroll_x.set)

    # Grid layout
    stats_tree.grid(row=0, column=0, sticky='nsew')
    stats_tree_scroll_y.grid(row=0, column=1, sticky='ns')
    stats_tree_scroll_x.grid(row=1, column=0, sticky='ew')
    stats_table_frame.grid_rowconfigure(0, weight=1)
    stats_table_frame.grid_columnconfigure(0, weight=1)

    # Add rows for each parameter and measure
    for test_num, short_name, full_name in params:
        param_column = test_num

        for measure in selected_measures:
            row_values = [f"{short_name} - {measure.upper()}"]

            for df in data_sources:
                if param_column in df.columns:
                    values = df[param_column].dropna().values
                    if len(values) > 0:
                        try:
                            if measure == "count":
                                val = len(values)
                            elif measure == "mean":
                                val = f"{np.mean(values):.4g}"
                            elif measure == "median":
                                val = f"{np.median(values):.4g}"
                            elif measure == "std":
                                val = f"{np.std(values):.4g}"
                            elif measure == "min":
                                val = f"{np.min(values):.4g}"
                            elif measure == "max":
                                val = f"{np.max(values):.4g}"
                            elif measure == "range":
                                val = f"{np.max(values) - np.min(values):.4g}"
                            elif measure == "cv":
                                mean_val = np.mean(values)
                                if mean_val != 0:
                                    val = f"{(np.std(values) / abs(mean_val)) * 100:.2f}%"
                                else:
                                    val = "N/A"
                            elif measure == "sigma1":
                                mean_val = np.mean(values)
                                std_val = np.std(values)
                                val = f"{mean_val-std_val:.3g} - {mean_val+std_val:.3g}"
                            elif measure == "sigma2":
                                mean_val = np.mean(values)
                                std_val = np.std(values)
                                val = f"{mean_val-2*std_val:.3g} - {mean_val+2*std_val:.3g}"
                            elif measure == "sigma3":
                                mean_val = np.mean(values)
                                std_val = np.std(values)
                                val = f"{mean_val-3*std_val:.3g} - {mean_val+3*std_val:.3g}"
                            elif measure == "p25":
                                val = f"{np.percentile(values, 25):.4g}"
                            elif measure == "p75":
                                val = f"{np.percentile(values, 75):.4g}"
                            elif measure == "p95":
                                val = f"{np.percentile(values, 95):.4g}"
                            elif measure == "iqr":
                                val = f"{np.percentile(values, 75) - np.percentile(values, 25):.4g}"
                            elif measure == "skewness":
                                val = f"{scipy_stats.skew(values):.3g}"
                            elif measure == "kurtosis":
                                val = f"{scipy_stats.kurtosis(values):.3g}"
                            else:
                                val = "N/A"
                        except Exception:
                            val = "Err"
                    else:
                        val = "N/A"
                else:
                    val = "N/A"
                row_values.append(val)

            stats_tree.insert('', 'end', values=row_values)

        # Add separator row (empty)
        stats_tree.insert('', 'end', values=["─" * 30] + ["─" * 10] * len(wafer_labels))

    # Update export button state
    stats_export_btn.config(state=tk.NORMAL)

def export_stats_table_to_excel():
    """Export statistics table to Excel"""
    global grouped_parameters, multi_wafer_stdf_data, multi_wafer_wafer_ids, current_stdf_data, current_wafer_id
    from scipy import stats as scipy_stats

    selected_group = stats_table_group_var.get()
    if selected_group == "-- Gruppe auswählen --":
        return

    # Determine data sources - use multi_wafer data (correct global variable name)
    if multi_wafer_stdf_data and len(multi_wafer_stdf_data) > 0:
        data_sources = multi_wafer_stdf_data
        wafer_labels = multi_wafer_wafer_ids if multi_wafer_wafer_ids else [f"Wafer {i+1}" for i in range(len(multi_wafer_stdf_data))]
    elif current_stdf_data is not None and not current_stdf_data.empty:
        data_sources = [current_stdf_data]
        wafer_labels = [current_wafer_id if current_wafer_id else "Wafer 1"]
    else:
        return

    if selected_group not in grouped_parameters:
        return

    params = grouped_parameters[selected_group]
    selected_measures = [key for key, var in stats_measures_vars.items() if var.get()]

    # Build data for Excel
    export_data = []
    for test_num, short_name, full_name in params:
        param_column = test_num

        for measure in selected_measures:
            row = {"Parameter": short_name, "Measure": measure.upper()}

            for wafer_idx, df in enumerate(data_sources):
                wafer_label = str(wafer_labels[wafer_idx])[:15]
                if param_column in df.columns:
                    values = df[param_column].dropna().values
                    if len(values) > 0:
                        try:
                            if measure == "count":
                                val = len(values)
                            elif measure == "mean":
                                val = np.mean(values)
                            elif measure == "median":
                                val = np.median(values)
                            elif measure == "std":
                                val = np.std(values)
                            elif measure == "min":
                                val = np.min(values)
                            elif measure == "max":
                                val = np.max(values)
                            elif measure == "range":
                                val = np.max(values) - np.min(values)
                            elif measure == "cv":
                                mean_val = np.mean(values)
                                val = (np.std(values) / abs(mean_val)) * 100 if mean_val != 0 else None
                            elif measure == "sigma1":
                                val = f"{np.mean(values)-np.std(values):.6g} - {np.mean(values)+np.std(values):.6g}"
                            elif measure == "sigma2":
                                val = f"{np.mean(values)-2*np.std(values):.6g} - {np.mean(values)+2*np.std(values):.6g}"
                            elif measure == "sigma3":
                                val = f"{np.mean(values)-3*np.std(values):.6g} - {np.mean(values)+3*np.std(values):.6g}"
                            elif measure == "p25":
                                val = np.percentile(values, 25)
                            elif measure == "p75":
                                val = np.percentile(values, 75)
                            elif measure == "p95":
                                val = np.percentile(values, 95)
                            elif measure == "iqr":
                                val = np.percentile(values, 75) - np.percentile(values, 25)
                            elif measure == "skewness":
                                val = scipy_stats.skew(values)
                            elif measure == "kurtosis":
                                val = scipy_stats.kurtosis(values)
                            else:
                                val = None
                        except Exception:
                            val = None
                    else:
                        val = None
                else:
                    val = None
                row[wafer_label] = val
            export_data.append(row)

    # Create DataFrame and save
    export_df = pd.DataFrame(export_data)

    file_path = filedialog.asksaveasfilename(
        defaultextension=".xlsx",
        filetypes=[("Excel files", "*.xlsx"), ("CSV files", "*.csv")],
        title="Statistik-Tabelle exportieren",
        initialfilename=f"Stats_{selected_group.replace(' ', '_')}.xlsx"
    )

    if file_path:
        if file_path.endswith('.csv'):
            export_df.to_csv(file_path, index=False)
        else:
            export_df.to_excel(file_path, index=False, sheet_name=selected_group[:30])
        print(f"Statistics table exported to {file_path}")

