# Storage for multiple slide configurations
grr_multi_slide_data = {}

# Base scale for Gage R&R
GRR_BASE_SCALE = 35

def calculate_grr_preview_scale(container_frame):
    """Calculate optimal scale for Gage R&R preview based on container size"""
    container_frame.update_idletasks()
    available_width = container_frame.winfo_width() - 20
    available_height = container_frame.winfo_height() - 100
    if available_width < 100 or available_height < 100:
        return GRR_BASE_SCALE
    scale_x = available_width / 13.333
    scale_y = available_height / 7.5
    optimal_scale = min(scale_x, scale_y)
    return max(25, min(optimal_scale, 60))

def get_default_grr_layout():
    """Get default layout boxes for Gage R&R"""
    return {
        "title": {"x": 0.3, "y": 0.15, "width": 12.733, "height": 0.5, "color": "#1976D2", "fill": "#E3F2FD", "enabled": True, "label": "Title"},
        "grr_summary": {"x": 0.3, "y": 0.7, "width": 6.0, "height": 3.0, "color": "#4CAF50", "fill": "#E8F5E9", "enabled": True, "label": "GRR Summary"},
        "variance": {"x": 6.5, "y": 0.7, "width": 6.5, "height": 3.0, "color": "#FF9800", "fill": "#FFF3E0", "enabled": True, "label": "Variance"},
        "charts": {"x": 0.3, "y": 3.8, "width": 6.0, "height": 3.0, "color": "#9C27B0", "fill": "#F3E5F5", "enabled": True, "label": "Charts"},
        "anova": {"x": 6.5, "y": 3.8, "width": 6.5, "height": 3.0, "color": "#2196F3", "fill": "#E3F2FD", "enabled": True, "label": "ANOVA"},
        "stats": {"x": 0.3, "y": 6.8, "width": 12.733, "height": 0.5, "color": "#607D8B", "fill": "#ECEFF1", "enabled": False, "label": "Statistics"},
    }

def create_grr_slide_tab(slide_index):
    """Create a new slide tab for Gage R&R with its own layout configuration"""
    global grr_multi_slide_data, grr_layout_boxes, grr_box_enable_vars, grr_preview_canvas

    tab_frame = ttk.Frame(grr_slides_notebook)
    grr_slides_notebook.add(tab_frame, text=f"Folie {slide_index + 1}")

    canvas_container = tk.Frame(tab_frame)
    canvas_container.pack(fill=tk.BOTH, expand=True, padx=5, pady=5)

    slide_layout_boxes = get_default_grr_layout()
    slide_box_enable_vars = {}
    for box_name, box_data in slide_layout_boxes.items():
        var = tk.BooleanVar(value=box_data["enabled"])
        slide_box_enable_vars[box_name] = var

    slide_drag_data = {"item": None, "x": 0, "y": 0, "mode": None, "box_name": None}

    current_scale = [GRR_BASE_SCALE]

    slide_canvas = tk.Canvas(
        canvas_container,
        width=int(13.333 * current_scale[0]),
        height=int(7.5 * current_scale[0]),
        bg="white",
        relief="solid",
        bd=1
    )
    slide_canvas.pack(pady=5, expand=True)

    def draw_slide_preview():
        slide_canvas.delete("all")
        scale = current_scale[0]
        slide_w = int(13.333 * scale)
        slide_h = int(7.5 * scale)
        slide_canvas.config(width=slide_w, height=slide_h)
        slide_canvas.create_rectangle(2, 2, slide_w-2, slide_h-2, fill="#F5F5F5", outline="#CCCCCC", width=2)
        for i in range(1, 13):
            x = i * scale
            slide_canvas.create_line(x, 0, x, slide_h, fill="#EEEEEE", dash=(2, 4))
        for i in range(1, 7):
            y = i * scale
            slide_canvas.create_line(0, y, slide_w, y, fill="#EEEEEE", dash=(2, 4))
        for box_name, box_data in slide_layout_boxes.items():
            if not slide_box_enable_vars.get(box_name, tk.BooleanVar(value=True)).get():
                continue
            x = box_data["x"] * scale
            y = box_data["y"] * scale
            w = box_data["width"] * scale
            h = box_data["height"] * scale
            slide_canvas.create_rectangle(x, y, x+w, y+h, fill=box_data["fill"], outline=box_data["color"], width=2, tags=(f"box_{box_name}", "box", "movable"))
            slide_canvas.create_text(x+w/2, y+h/2, text=box_data["label"], font=("Helvetica", 8, "bold"), fill=box_data["color"], tags=(f"label_{box_name}",))
            handle_size = 16
            slide_canvas.create_rectangle(x+w-handle_size, y+h-handle_size, x+w, y+h, fill=box_data["color"], outline="white", width=2, tags=(f"handle_{box_name}", "handle"))
            slide_canvas.create_line(x+w-handle_size+4, y+h-4, x+w-4, y+h-handle_size+4, fill="white", width=2, tags=(f"handle_{box_name}",))
            slide_canvas.create_text(x+w/2, y+h+10, text=f"{box_data['width']:.1f}\" × {box_data['height']:.1f}\"", font=("Helvetica", 6), fill="#888888")

    def on_slide_press(event):
        nonlocal slide_drag_data
        handle_items = slide_canvas.find_overlapping(event.x-10, event.y-10, event.x+10, event.y+10)
        for item in handle_items:
            tags = slide_canvas.gettags(item)
            for tag in tags:
                if tag.startswith("handle_"):
                    box_name = tag.replace("handle_", "")
                    if box_name in slide_layout_boxes:
                        slide_drag_data = {"item": item, "x": event.x, "y": event.y, "mode": "resize", "box_name": box_name}
                        slide_canvas.config(cursor="bottom_right_corner")
                        return
        items = slide_canvas.find_overlapping(event.x-2, event.y-2, event.x+2, event.y+2)
        for item in items:
            tags = slide_canvas.gettags(item)
            if "movable" in tags:
                for tag in tags:
                    if tag.startswith("box_") and not tag.startswith("box_name"):
                        box_name = tag.replace("box_", "")
                        if box_name in slide_layout_boxes:
                            slide_drag_data = {"item": item, "x": event.x, "y": event.y, "mode": "move", "box_name": box_name}
                            slide_canvas.config(cursor="fleur")
                            return

    def on_slide_drag(event):
        nonlocal slide_drag_data
        if slide_drag_data["box_name"] is None:
            return
        box_name = slide_drag_data["box_name"]
        dx = event.x - slide_drag_data["x"]
        dy = event.y - slide_drag_data["y"]
        dx_inches = dx / current_scale[0]
        dy_inches = dy / current_scale[0]
        if slide_drag_data["mode"] == "move":
            new_x = max(0, min(13.333 - slide_layout_boxes[box_name]["width"], slide_layout_boxes[box_name]["x"] + dx_inches))
            new_y = max(0, min(7.5 - slide_layout_boxes[box_name]["height"], slide_layout_boxes[box_name]["y"] + dy_inches))
            slide_layout_boxes[box_name]["x"] = round(new_x, 2)
            slide_layout_boxes[box_name]["y"] = round(new_y, 2)
        elif slide_drag_data["mode"] == "resize":
            new_w = max(0.5, min(13.333 - slide_layout_boxes[box_name]["x"], slide_layout_boxes[box_name]["width"] + dx_inches))
            new_h = max(0.3, min(7.5 - slide_layout_boxes[box_name]["y"], slide_layout_boxes[box_name]["height"] + dy_inches))
            slide_layout_boxes[box_name]["width"] = round(new_w, 2)
            slide_layout_boxes[box_name]["height"] = round(new_h, 2)
        slide_drag_data["x"] = event.x
        slide_drag_data["y"] = event.y
        draw_slide_preview()

    def on_slide_release(event):
        nonlocal slide_drag_data
        slide_drag_data = {"item": None, "x": 0, "y": 0, "mode": None, "box_name": None}
        slide_canvas.config(cursor="")

    slide_canvas.bind("<ButtonPress-1>", on_slide_press)
    slide_canvas.bind("<B1-Motion>", on_slide_drag)
    slide_canvas.bind("<ButtonRelease-1>", on_slide_release)

    checkbox_frame = tk.LabelFrame(tab_frame, text="Elemente", font=("Helvetica", 9))
    checkbox_frame.pack(fill=tk.X, padx=5, pady=5)

    for box_name, box_data in slide_layout_boxes.items():
        cb = tk.Checkbutton(
            checkbox_frame,
            text=box_data["label"],
            variable=slide_box_enable_vars[box_name],
            font=("Helvetica", 8),
            fg=box_data["color"],
            command=draw_slide_preview
        )
        cb.pack(side=tk.LEFT, padx=3)

    preset_frame = tk.Frame(tab_frame)
    preset_frame.pack(fill=tk.X, padx=5, pady=5)

    def apply_slide_preset(preset):
        presets = {
            "Standard": {"title": (0.3, 0.15, 12.733, 0.5), "grr_summary": (0.3, 0.7, 6.0, 3.0), "variance": (6.5, 0.7, 6.5, 3.0), "charts": (0.3, 3.8, 6.0, 3.0), "anova": (6.5, 3.8, 6.5, 3.0), "stats": (0.3, 6.8, 12.733, 0.5)},
            "Full": {"title": (0.3, 0.15, 12.733, 0.5), "grr_summary": (0.3, 0.7, 12.7, 6.5), "variance": (0.3, 0.7, 12.7, 6.5), "charts": (0.3, 0.7, 12.7, 6.5), "anova": (0.3, 0.7, 12.7, 6.5), "stats": (0.3, 6.8, 12.733, 0.5)},
        }
        if preset in presets:
            for box_name, vals in presets[preset].items():
                if box_name in slide_layout_boxes:
                    slide_layout_boxes[box_name]["x"], slide_layout_boxes[box_name]["y"] = vals[0], vals[1]
                    slide_layout_boxes[box_name]["width"], slide_layout_boxes[box_name]["height"] = vals[2], vals[3]
            draw_slide_preview()

    tk.Label(preset_frame, text="Presets:", font=("Helvetica", 8, "bold")).pack(side=tk.LEFT, padx=2)
    for preset in ["Standard", "Full"]:
        tk.Button(preset_frame, text=preset, font=("Helvetica", 7), command=lambda p=preset: apply_slide_preset(p)).pack(side=tk.LEFT, padx=2)

    tk.Label(tab_frame, text="💡 Ziehen = Verschieben, Ecke = Größe ändern", font=("Helvetica", 7), fg="#666666").pack(pady=2)

    def on_container_resize(event):
        new_scale = calculate_grr_preview_scale(canvas_container)
        if abs(new_scale - current_scale[0]) > 2:
            current_scale[0] = new_scale
            draw_slide_preview()

    canvas_container.bind("<Configure>", on_container_resize)

    grr_multi_slide_data[slide_index] = {
        "tab_frame": tab_frame,
        "canvas": slide_canvas,
        "canvas_container": canvas_container,
        "layout_boxes": slide_layout_boxes,
        "box_enable_vars": slide_box_enable_vars,
        "draw_func": draw_slide_preview,
        "current_scale": current_scale
    }

    if slide_index == 0:
        grr_layout_boxes = slide_layout_boxes
        grr_box_enable_vars = slide_box_enable_vars
        grr_preview_canvas = slide_canvas

    draw_slide_preview()
    return tab_frame

def update_grr_slide_tabs(*args):
    """Update Gage R&R slide tabs based on spinbox value"""
    global grr_multi_slide_data
    try:
        target_count = grr_slide_count_var.get()
    except:
        return

    current_count = len(grr_multi_slide_data)

    if target_count > current_count:
        for i in range(current_count, target_count):
            create_grr_slide_tab(i)
    elif target_count < current_count:
        for i in range(current_count - 1, target_count - 1, -1):
            if i in grr_multi_slide_data:
                grr_slides_notebook.forget(grr_multi_slide_data[i]["tab_frame"])
                del grr_multi_slide_data[i]

    # Update group listbox to reflect new slide counts
    try:
        refresh_grr_group_listbox()
        update_grr_report_summary()
    except NameError:
        pass

