# Config file for saving template path
def get_config_path():
    """Get path to config file"""
    return os.path.join(os.path.dirname(__file__), "wafermap_config.json")

def save_template_config(template_path):
    """Save template path to config"""
    config_path = get_config_path()
    config = {}
    if os.path.exists(config_path):
        try:
            with open(config_path, 'r') as f:
                config = json.load(f)
        except:
            pass
    config['pptx_template_path'] = template_path
    try:
        with open(config_path, 'w') as f:
            json.dump(config, f, indent=2)
    except Exception as e:
        print(f"Error saving config: {e}")

def load_template_config():
    """Load template path from config"""
    config_path = get_config_path()
    if os.path.exists(config_path):
        try:
            with open(config_path, 'r') as f:
                config = json.load(f)
                template_path = config.get('pptx_template_path', '')
                if template_path and os.path.exists(template_path):
                    pptx_template_path_var.set(template_path)
                    pptx_use_template_var.set(True)
                    template_status_label.config(text=f"✅ Template: {os.path.basename(template_path)}", fg="green")
        except Exception as e:
            print(f"Error loading config: {e}")

# Load template config on startup
