                                    grid, x_min, y_min, x_max, y_max, gw, gh = _compute_grid_fast(plot_data, col_to_use)
                                    ax.imshow(grid, cmap="viridis", aspect="equal", origin="upper", vmin=vmin, vmax=vmax)
