def convert_stdf_to_csv_batch():
    """Convert multiple STDF files to CSV format"""
    global stdf_csv_status_var

    # Get selected files
    file_paths = filedialog.askopenfilenames(
        title="Select STDF Files to Convert",
        filetypes=[("STDF files", "*.stdf *.std"), ("All files", "*.*")],
    )

    if not file_paths:
        return

    # Get output directory
    output_dir = filedialog.askdirectory(title="Select Output Directory for CSV Files")
    if not output_dir:
        return

    stdf_csv_status_var.set(f"Converting {len(file_paths)} files...")
    stdf_csv_progress_var.set(0)
    stdf_csv_file_listbox.delete(0, tk.END)

    # Update UI
    main_win.update_idletasks()

    converted_count = 0
    failed_files = []

    for idx, stdf_path in enumerate(file_paths):
        try:
            filename = os.path.basename(stdf_path)
            stdf_csv_file_listbox.insert(tk.END, f"Converting: {filename}...")
            stdf_csv_file_listbox.see(tk.END)
            main_win.update_idletasks()

            # Load STDF data using CSV export function
            df, wafer_id, test_params, test_limits_data, wafer_config = load_single_stdf_file_for_csv(stdf_path)

            if df is not None and len(df) > 0:
                # Create output filename
                base_name = os.path.splitext(filename)[0]
                csv_filename = f"{base_name}.csv"
                csv_path = os.path.join(output_dir, csv_filename)

                # Save to CSV
                df.to_csv(csv_path, index=False)

                converted_count += 1
                stdf_csv_file_listbox.delete(tk.END)
                stdf_csv_file_listbox.insert(tk.END, f"✓ {filename} -> {csv_filename} ({len(df)} dies)")
            else:
                failed_files.append(filename)
                stdf_csv_file_listbox.delete(tk.END)
                stdf_csv_file_listbox.insert(tk.END, f"✗ {filename} - No data")

        except Exception as e:
            failed_files.append(filename)
            stdf_csv_file_listbox.delete(tk.END)
            stdf_csv_file_listbox.insert(tk.END, f"✗ {filename} - Error: {str(e)[:50]}")

        # Update progress
        progress = int((idx + 1) / len(file_paths) * 100)
        stdf_csv_progress_var.set(progress)
        main_win.update_idletasks()

    # Final status
    if failed_files:
        stdf_csv_status_var.set(f"Done! Converted {converted_count}/{len(file_paths)} files. {len(failed_files)} failed.")
    else:
        stdf_csv_status_var.set(f"Success! Converted {converted_count} files to CSV.")

    stdf_csv_file_listbox.insert(tk.END, "")
    stdf_csv_file_listbox.insert(tk.END, f"=== Conversion Complete ===")
    stdf_csv_file_listbox.insert(tk.END, f"Output directory: {output_dir}")
    stdf_csv_file_listbox.see(tk.END)


def load_single_stdf_file_for_csv(stdf_path):
    """Load a single STDF file and return DataFrame with ALL test data for CSV export.
    Uses test names as column headers for proper loading."""
    if STDF_MODULE is None:
        return None, None, {}, {}, {}

    try:
        die_data = {}  # (x, y) -> {'x': x, 'y': y, 'bin': bin, ...}
        test_info = {}  # test_num -> test_name
        test_limits_dict = {}
        wafer_id = os.path.basename(stdf_path).replace('.stdf', '').replace('.std', '')
        wafer_config = {}

        current_die_tests = {}

        def extract_group_from_test_name(test_name):
            """Extract group from test name prefix (DC_, Optical_, etc.)"""
            if not test_name:
                return "Other"
            name_str = str(test_name).upper()

            # Known group prefixes
            known_groups = {
                'DC_': 'DC',
                'OPTICAL': 'Optical',
                'OPTIC': 'Optical',
                'ANALOG': 'Analog',
                'DIGITAL': 'Digital',
                'FUNC': 'Function',
                'FUNCTION': 'Function',
                'POWER': 'Power',
                'INITIALIZE': 'Initialize',
                'INIT_': 'Initialize',
                'SOT_': 'SOT',
                'STD_': 'STD',
                'PIB': 'PIB',
                'PROBECARD': 'Probecard',
                'TRUETEST': 'TrueTest',
                'CAMERA': 'Camera',
                'SPECTROMETER': 'Spectrometer',
            }

            for prefix, group in known_groups.items():
                if name_str.startswith(prefix):
                    return group

            # If underscore present, use first part as group
            if '_' in name_str:
                first_part = name_str.split('_')[0]
                if len(first_part) >= 2:
                    return first_part.title()

            return "Other"

        with open(stdf_path, "rb") as f:
            for record in STDF_MODULE.records_from_file(f):
                record_type = type(record).__name__

                # MIR - Master Information Record
                if record_type == "MIR":
                    try:
                        lot_id = record.get_value("LOT_ID") if hasattr(record, "get_value") else getattr(record, "LOT_ID", "")
                        if lot_id:
                            wafer_id = str(lot_id)
                    except:
                        pass

                # WIR - Wafer Information Record
                if record_type == "WIR":
                    try:
                        wir_wafer_id = record.get_value("WAFER_ID") if hasattr(record, "get_value") else getattr(record, "WAFER_ID", "")
                        if wir_wafer_id:
                            wafer_id = str(wir_wafer_id)
                    except:
                        pass

                # PIR - Part Information Record (start of new die)
                if record_type == "PIR":
                    current_die_tests = {}

                # PTR - Parametric Test Record
                if record_type == "PTR":
                    try:
                        test_num = record.get_value("TEST_NUM") if hasattr(record, "get_value") else record.TEST_NUM
                        result = record.get_value("RESULT") if hasattr(record, "get_value") else record.RESULT
                        test_name = record.get_value("TEST_TXT") if hasattr(record, "get_value") else getattr(record, "TEST_TXT", "")

                        if test_num is not None:
                            # Store test name
                            if test_num not in test_info and test_name:
                                test_info[test_num] = str(test_name)

                            # Store result for current die
                            current_die_tests[test_num] = result

                            # Get limits
                            if test_num not in test_limits_dict:
                                try:
                                    lo_limit = record.get_value("LO_LIMIT") if hasattr(record, "get_value") else getattr(record, "LO_LIMIT", None)
                                    hi_limit = record.get_value("HI_LIMIT") if hasattr(record, "get_value") else getattr(record, "HI_LIMIT", None)
                                    units = record.get_value("UNITS") if hasattr(record, "get_value") else getattr(record, "UNITS", "")
                                    test_limits_dict[test_num] = {'lo_limit': lo_limit, 'hi_limit': hi_limit, 'units': units}
                                except:
                                    pass
                    except:
                        pass

                # PRR - Part Results Record (end of die, get coordinates and bin)
                if record_type == "PRR":
                    try:
                        x = record.get_value("X_COORD") if hasattr(record, "get_value") else record.X_COORD
                        y = record.get_value("Y_COORD") if hasattr(record, "get_value") else record.Y_COORD
                        hbin = record.get_value("HARD_BIN") if hasattr(record, "get_value") else record.HARD_BIN
                        sbin = record.get_value("SOFT_BIN") if hasattr(record, "get_value") else record.SOFT_BIN

                        die_key = (x, y)

                        # Store die with all its test results
                        die_data[die_key] = {
                            'x': x,
                            'y': y,
                            'bin': hbin,
                            'sbin': sbin
                        }
                        # Add all test results for this die
                        # Format: TestName_TestNum (similar to tester CSV format)
                        for test_num, result in current_die_tests.items():
                            test_name = test_info.get(test_num, f"Test_{test_num}")
                            # Clean test name - remove spaces and problematic characters
                            clean_name = str(test_name).split()[0] if test_name else f"Test_{test_num}"
                            clean_name = clean_name.replace(',', '_').replace('"', '').replace("'", "").replace(' ', '_')
                            # Column format: TestName_TestNum (like tester output)
                            col_name = f"{clean_name}_{test_num}"
                            die_data[die_key][col_name] = result

                        current_die_tests = {}
                    except:
                        pass

        # Convert to DataFrame
        if die_data:
            df = pd.DataFrame(list(die_data.values()))

            # Reorder columns: x, y, bin first, then test columns sorted
            base_cols = ['x', 'y', 'bin', 'sbin']
            test_cols = sorted([c for c in df.columns if c not in base_cols])
            all_cols = [c for c in base_cols if c in df.columns] + test_cols
            df = df[all_cols]

            return df, wafer_id, test_info, test_limits_dict, wafer_config

        return None, wafer_id, {}, {}, {}

    except Exception as e:
        print(f"Error loading {stdf_path}: {e}")
        import traceback
        traceback.print_exc()
        return None, None, {}, {}, {}


