# Convert button
def start_stdf_conversion():
    """Start conversion of selected STDF files"""
    global stdf_csv_selected_files

    if not stdf_csv_selected_files:
        stdf_csv_status_var.set("⚠️ Keine Dateien ausgewählt!")
        return

    output_dir = stdf_csv_output_path_var.get()
    if not output_dir:
        output_dir = filedialog.askdirectory(title="Ausgabe-Verzeichnis auswählen")
        if not output_dir:
            return
        stdf_csv_output_path_var.set(output_dir)

    # Clear conversion log
    stdf_csv_file_listbox.delete(0, tk.END)
    stdf_csv_progress_var.set(0)
    stdf_csv_status_var.set(f"Konvertiere {len(stdf_csv_selected_files)} Dateien...")
    main_win.update_idletasks()

    converted_count = 0
    failed_files = []
    total_files = len(stdf_csv_selected_files)

    for idx, stdf_path in enumerate(stdf_csv_selected_files):
        try:
            filename = os.path.basename(stdf_path)

            # Show "Converting" status in log
            stdf_csv_file_listbox.insert(tk.END, f"⏳ Konvertiere: {filename}...")
            stdf_csv_file_listbox.see(tk.END)
            stdf_csv_file_listbox.itemconfig(tk.END, fg='blue')
            main_win.update_idletasks()

            # Load STDF data
            df, wafer_id, test_params, test_limits_data, wafer_config = load_single_stdf_file_for_csv(stdf_path)

            if df is not None and len(df) > 0:
                # Create output filename
                base_name = os.path.splitext(filename)[0]
                csv_filename = f"{base_name}.csv"
                csv_path = os.path.join(output_dir, csv_filename)

                # Save to CSV
                df.to_csv(csv_path, index=False)

                converted_count += 1
                # Update status in log
                stdf_csv_file_listbox.delete(tk.END)
                stdf_csv_file_listbox.insert(tk.END, f"✅ {filename} → {csv_filename} ({len(df)} Dies)")
                stdf_csv_file_listbox.itemconfig(tk.END, fg='green')
            else:
                failed_files.append(filename)
                stdf_csv_file_listbox.delete(tk.END)
                stdf_csv_file_listbox.insert(tk.END, f"❌ {filename} - Keine Daten gefunden")
                stdf_csv_file_listbox.itemconfig(tk.END, fg='red')

        except Exception as e:
            failed_files.append(filename)
            stdf_csv_file_listbox.delete(tk.END)
            stdf_csv_file_listbox.insert(tk.END, f"❌ {filename} - Fehler: {str(e)[:50]}")
            stdf_csv_file_listbox.itemconfig(tk.END, fg='red')

        # Update progress
        progress = int((idx + 1) / total_files * 100)
        stdf_csv_progress_var.set(progress)
        main_win.update_idletasks()

    # Final status
    stdf_csv_file_listbox.insert(tk.END, "")
    stdf_csv_file_listbox.insert(tk.END, "═" * 50)
    if failed_files:
        stdf_csv_status_var.set(f"Fertig! {converted_count}/{total_files} konvertiert. {len(failed_files)} fehlgeschlagen.")
